INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-01', 'قتل', 'مقتل صاحب المركب', 'عم سيد صاحب مركب سياحية في النيل اتلقى ميت على المركب بتاعته الصبح بدري. الدكتور قال إنه اتضرب على دماغه بحاجة تقيلة وبعدين اترمى في المية بس جسمه طلع على سطح المركب تاني. كان فيه خمس ناس معاه على المركب بالليل في رحلة عشا خاصة. محدش سمع حاجة ومحدش شاف حاجة.', 5, 2, 'كريم، هاجر', 'لقوا بقع دم على حاجز المركب الجانبي اللي جنب المطبخ; الكاميرا اللي على الكوبري صورت المركب وهي بتتحرك من مكانها الساعة ٢ بالليل مع إن محدش كان المفروض يسوقها; واحد من الجيران على النيل سمع صوت خناقة جاي من المركب حوالي الساعة ١ بالليل; تليفون عم سيد فيه رسالة بتقول "هنخلص الموضوع بكره" من نمرة مش متسجلة; لقوا كوباية شاي فيها أثر منوم في كابينة عم سيد', 'كريم كان مديون لعم سيد بمبلغ كبير وعم سيد كان بيهدده يقدم بلاغ; هاجر اتصورت بكاميرا المركب وهي نازلة المطبخ الساعة ١٢:٤٥ بالليل وقالت إنها كانت نايمة; لقوا ماسورة حديد تحت كرسي في الكابينة الخلفية عليها بصمات اتمسحت بعجلة; رسالة على واتساب بين كريم وهاجر قبلها بيومين بيقولوا "لازم نتكلم عن موضوع عم سيد"; واحد من عمال المرسى قال إنه شاف شنطة سودا اتشالت من المركب الساعة ٣ الفجر', 'تحليل الـ DNA على الماسورة طلع فيه أثر عرق مطابق لكريم; كاميرا المرسى صورت هاجر وهي شايلة الشنطة السودا الساعة ٣ الفجر; المنوم اللي في الشاي نفس النوع اللي هاجر بتاخده كدواء من الصيدلية; فلوس كتير اتحولت من حساب عم سيد لحساب مجهول قبل ما يموت بساعة والتحويل اتعمل من تليفون كريم; شهادة عامل المرسى إنه سمع كريم بيقول لهاجر "خلاص كل حاجة اتظبطت"', 'كريم كان مديون لعم سيد ب٥٠٠ ألف جنيه ومكانش يقدر يسدد. اتفق مع هاجر إنها تحط منوم في شاي عم سيد وبعد ما نام كريم ضربه بالماسورة على دماغه. هاجر ساعدته يرمي الأدلة في شنطة ونزلتها المرسى. كريم حول فلوس من حساب عم سيد قبل ما حد يعرف إنه مات.', 'محمد — كان بيشتغل في تجارة مش قانونية وعم سيد كان عارف وبيهدده يفضحه; نور — كانت في علاقة سرية مع عم سيد وخايفة جوزها يعرف; أحمد — عم سيد طرده من الشغل قبلها بأسبوع وكان ناوي يقاضيه', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-02', 'قتل', 'جريمة فيلا الساحل', 'في عزومة صيفي في فيلا في الساحل الشمالي، صاحب الفيلا طارق باشا اتلقى ميت في الجاكوزي بتاع الفيلا. الدكتور قال إنه اتسمم والسم كان في كاس العصير بتاعه. كان فيه خمس ناس في العزومة ومحدش غادر الفيلا من بالليل لحد ما لقوا الجثة الصبح.', 5, 2, 'سارة، عمرو', 'لقوا كاس عصير مانجو فيه أثر مادة سامة جنب الجاكوزي; باب مخزن الأدوية بتاع الفيلا كان مفتوح والقفل متكسر; طارق باشا كان لابس ساعته الغالية بس محفظته مكانتش معاه; كاميرات الفيلا اتقطعت من الساعة ١١ بالليل لحد ٣ الفجر; واحد من الجيران سمع صوت مزيكا عالية جاية من الفيلا لحد متأخر', 'سارة شغالة صيدلانية وعندها علم بالمواد السامة وأنواعها; عمرو كان شريك طارق باشا في مشروع عقاري خسران وكان بينهم خلاف مادي كبير; لقوا جوانتي طبي في سلة الزبالة بتاعة المطبخ عليه أثر نفس المادة السامة; رسايل على تليفون طارق بتوضح إنه كان ناوي يفسخ الشراكة مع عمرو ويطالبه بفلوسه; تليفون سارة فيه سيرش على جوجل عن "جرعة قاتلة من" قبل العزومة بيوم', 'الجوانتي الطبي اللي في الزبالة عليه بصمة جزئية مطابقة لسارة; عمرو اتصور بكاميرا الجار وهو بيرمي حاجة في البحر الساعة ٢ بالليل والحاجة دي طلعت إزازة الدوا اللي فيها السم; سارة وعمرو كانوا في علاقة سرية من سنتين وطارق اكتشف واتهددهم; فيه شهادة من الخدامة إن سارة هي اللي عملت العصير لطارق بنفسها; عمرو هو اللي كسر قفل المخزن وطلع المادة السامة وسلمها لسارة', 'سارة وعمرو كانوا في علاقة سرية وطارق اكتشف وهددهم يفضحهم ويخرب حياتهم. عمرو كسر مخزن الأدوية وجاب المادة السامة وسارة بخبرتها كصيدلانية حسبت الجرعة وحطتها في عصير المانجو. عمرو رمى الإزازة في البحر وسارة رمت الجوانتي. قطعوا الكاميرات عشان محدش يشوف حاجة.', 'فاطمة — كانت طليقة طارق وكان بينهم قضية نفقة شرسة ولسه بتهدده; مصطفى — كان بيلعب قمار وخسران فلوس كتير وطارق رفض يسلفه; شريف — عنده سوابق وكان طارق بيهدده يبلغ عنه لو مرجعش فلوسه', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-03', 'قتل', 'قتيل المسرح', 'المخرج الكبير أبو طارق اتلقى ميت في غرفة الملابس بتاعة مسرح وسط البلد بعد عرض الافتتاح. اتخنق بحبل من حبال الستارة. كل الممثلين والفنيين كانوا لسه موجودين في المسرح وقت ما لقوا الجثة. البوليس قفل المسرح ومحدش يطلع.', 5, 2, 'ياسمين، مصطفى', 'لقوا حبل الستارة ملفوف على رقبة أبو طارق وعليه بودرة بيضا شبه بودرة الوش; كان فيه خناقة كبيرة بين أبو طارق وواحد من الفريق قبل العرض سمعها كل اللي في الكواليس; باب غرفة الملابس مكانش مقفول بس النور كان مطفي جواها; لقوا ورقة ممزقة في سلة الزبالة مكتوب فيها "مش هسكت تاني"; تليفون أبو طارق كان متكسر ومرمي جنب الجثة', 'ياسمين هي الممثلة الرئيسية وأبو طارق كان بيهددها يشيلها من المسرحية لو مسمعتش الكلام; مصطفى فني الإضاءة وهو اللي عنده وصول لحبال الستارة كلها; البودرة البيضا على الحبل طلعت بودرة مكياج من نوع غالي بتستخدمه ياسمين بس; كاميرات الكواليس صورت مصطفى وهو بيطفي نور غرفة الملابس قبل ما يلاقوا الجثة ب٢٠ دقيقة; الورقة الممزقة خطها طلع خط ياسمين', 'بصمات مصطفى لقوها على الحبل اللي اتخنق بيه أبو طارق; ياسمين اعترفت لصاحبتها في رسالة إن أبو طارق كان بيتحرش بيها وإنها "هتخلص منه"; مصطفى وياسمين اتقابلوا في كافيه قبل يوم العرض وشهود شافوهم بيتكلموا بعصبية; الورقة الممزقة كانت شكوى رسمية من ياسمين ضد أبو طارق لكنها مبعتتهاش; تسجيل صوتي على تليفون مصطفى المتكسر فيه أبو طارق بيقوله "هطردك وتنام في الشارع"', 'أبو طارق كان بيتحرش بياسمين وبيهدد مصطفى بالطرد لأنه شاف اللي بيحصل. ياسمين ومصطفى اتفقوا يخلصوا منه. مصطفى طفى النور في غرفة الملابس وجاب الحبل، وياسمين استدرجت أبو طارق للغرفة. مصطفى خنقه بالحبل وياسمين كسرت تليفونه عشان فيه تسجيلات تدينها.', 'هدى — كانت بتسرق من صندوق المسرح وأبو طارق اكتشف وكان هيبلغ عنها; عمرو — كان مديون وباع تذاكر في السوق السودا وأبو طارق عرف; كريم — كان عايز دور البطولة وأبو طارق رفض واختار حد تاني', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-04', 'قتل', 'مقتل الدكتور في العيادة', 'الدكتور حازم صاحب عيادة أسنان في المهندسين اتلقى ميت في العيادة بتاعته بعد آخر ميعاد بالليل. اتضرب بآلة حادة في راسه. كان فيه تلات ناس في العيادة وقت الحادثة: الممرضة، المريض الأخير، والسكيورتي بتاع العمارة.', 3, 1, 'نور', 'لقوا آلة حادة من أدوات الأسنان عليها دم جنب الكرسي; كاميرا العمارة بتوضح إن محدش دخل أو خرج من العيادة من الساعة ٨ لحد ١٠ بالليل; كان فيه فلوس كتير في درج المكتب ومحدش أخدها; باب العيادة الخلفي كان مفتوح على السلم; تليفون الدكتور حازم فيه مكالمة من نمرة مجهولة استمرت ٣ دقايق قبل ما يموت بنص ساعة', 'نور الممرضة كان عندها مفتاح العيادة الخلفي وهي الوحيدة اللي تقدر تفتحه; لقوا جوانتي طبي في الحمام عليه بقع دم خفيفة; نور قدمت استقالتها قبلها بيومين والدكتور حازم رفض وهددها إنه هيخرب سمعتها في المجال; سجلات العيادة بتقول إن نور هي اللي كانت لسه موجودة في غرفة الأدوات وقت الحادثة; المكالمة المجهولة طلعت من تليفون مقفول تم شراؤه كاش من يومين', 'الجوانتي اللي في الحمام عليه بصمة جزئية من نور; التليفون المجهول اللي اتصل بالدكتور اتشرى من محل قريب من بيت نور; شهادة جارة نور إنها سمعتها بتقول "هخلص الموضوع ده بأي طريقة"; سجل المكالمات بتاع نور فيه اتصالات كتير بمحامي قضايا جنائية قبل الحادثة بأسبوع; نور كانت بتحول فلوس لحساب مجهول كل شهر والدكتور حازم اكتشف وهددها', 'نور كانت بتاخد فلوس من العيادة من سنين والدكتور حازم اكتشف وهددها إنه هيبلغ عنها ويسجنها. قررت تخلص منه قبل ما يعمل حاجة. استنته لحد ما المريض الأخير مشي، ودخلت غرفة الأدوات وجابت الآلة الحادة وضربته. لبست جوانتي عشان بصماتها متبانش بس نسيت ترمي الجوانتي بره العيادة.', 'أحمد (المريض) — كان بيزور العيادة بهوية مزورة عشان عنده مشاكل قانونية وخايف حد يعرف; باسم (السكيورتي) — كان بينام في الشيفت وبيسيب العمارة من غير حراسة ومش عايز حد يعرف', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-05', 'قتل', 'عزومة الموت في شبرا', 'الحاج عبدالله صاحب محل دهب في شبرا عمل عزومة عشا في بيته لأقاربه. بعد العشا بساعة لقوه مرمي في أوضة النوم ميت. الدكتور قال إنه اتسمم والسم كان في الأكل أو الشرب. خمس ناس كانوا في العزومة ومحدش سابها.', 5, 2, 'فاطمة، طارق', 'الأكل كان محضر في البيت وكل الناس أكلت من نفس الأطباق بس الحاج عبدالله كان الوحيد اللي شرب من إبريق شاي خاص بيه عشان عنده سكر; لقوا أثر مادة سامة في الإبريق بتاع الشاي; باب المطبخ كان مفتوح طول الوقت وأي حد يقدر يدخل; الحاج عبدالله كان لسه مغير وصيته قبلها بأسبوع وشال اسم طارق ابنه; لقوا علبة دوا فاضية في سلة زبالة المطبخ', 'فاطمة مرات الحاج عبدالله هي اللي عملت الشاي بنفسها وقالت محدش غيرها دخل المطبخ; طارق ابنه كان عارف إنه اتشال من الوصية وكان زعلان جداً; علبة الدوا الفاضية طلعت دوا للقلب بجرعة كبيرة ممكن تقتل ولو اتحطت في سائل سخن; فيه كاميرا جوا بتوضح إن طارق دخل المطبخ وفاطمة كانت جواه والاتنين قعدوا ٥ دقايق لوحدهم; رسالة على تليفون فاطمة لطارق بتقول "بعد بكره هتتحل كل المشاكل"', 'تحليل الشاي أثبت إن السم اتحط وهو سخن يعني في المطبخ مش بعد ما اتقدم; الكاميرا بتوضح إن فاطمة فتحت علبة الدوا وطارق حطها في الإبريق; فاطمة كانت مستفيدة من بوليصة تأمين على حياة الحاج عبدالله بمليون جنيه; طارق كان مديون ومحتاج ورثه بسرعة; شهادة الجارة إنها سمعت فاطمة بتقول لطارق "أبوك راجل ظالم ومستاهل اللي هيحصله"', 'فاطمة وطارق اتفقوا مع بعض إنهم يتخلصوا من الحاج عبدالله. فاطمة عملت الشاي وطارق حط فيه جرعة كبيرة من دوا القلب اللي بتقتل لو اتاخدت بكمية كبيرة. فاطمة كانت عايزة فلوس التأمين وطارق كان عايز ميراثه اللي أبوه شاله من الوصية.', 'مي — كانت بتخون جوزها مع واحد والحاج عبدالله عرف وهددها يقول لجوزها; حسن — كان بيسرق من محل الدهب بتاع الحاج عبدالله وخايف ينفضح; ليلى — كانت زعلانة إن الحاج عبدالله مديها ورث أقل من إخواتها', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-06', 'قتل', 'مقتل البواب', 'عم حسن بواب العمارة في الدقي من ٢٠ سنة اتلقى مقتول في أوضة البدروم اللي بينام فيها. اتضرب بحاجة تقيلة على راسه. كان فيه تلات سكان في العمارة وقت الحادثة اللي حصلت بالليل. عم حسن كان راجل طيب بس كان بيعرف أسرار كل الناس في العمارة.', 3, 1, 'شريف', 'لقوا شاكوش مرمي في سلة الزبالة بتاعة العمارة عليه دم; باب البدروم مكانش متكسر يعني اللي دخل كان عنده مفتاح أو عم حسن فتحله; لقوا ورقة في جيب عم حسن مكتوب فيها أرقام وأسامي شبه سجل حسابات; العمارة مفيهاش كاميرات بس الشارع فيه كاميرا صورت حد نازل من العمارة الساعة ١ بالليل; محفظة عم حسن مكانتش موجودة', 'شريف ساكن في الدور التالت ومعروف إنه بيتخانق مع عم حسن كتير على مواضيع فلوس; الورقة اللي في جيب عم حسن فيها اسم شريف جنب مبلغ ٢٠ ألف جنيه; الشاكوش من نفس النوع اللي شريف بيستخدمه في شغله كنجار; كاميرا الشارع صورت راجل شبه شريف في البنية نازل الساعة ١ بالليل; شريف قال للبوليس إنه كان نايم بس جاره سمع باب شقته بيتقفل الساعة ١٢:٤٥', 'بصمة شريف لقوها على يد الباب بتاع البدروم; شريف كان بيدفع لعم حسن فلوس كل شهر عشان يسكت على إنه بيشغل الشقة ورشة من غير ترخيص; عم حسن طلب فلوس أكتر الشهر ده وشريف رفض وعم حسن هدده يبلغ عنه; الجار بتاع شريف سمعه بيتكلم في التليفون وبيقول "عم حسن لازم يتعامل معاه"; محفظة عم حسن لقوها في صندوق الزبالة بتاع الدور التالت اللي شريف ساكن فيه', 'شريف كان بيشغل شقته ورشة نجارة من غير ترخيص وعم حسن كان بياخد منه فلوس كل شهر عشان يسكت. لما عم حسن طلب أكتر وهدده يبلغ، شريف نزل البدروم بالليل وضربه بالشاكوش بتاعه على راسه. أخد محفظته عشان يبان إنها سرقة ورماها في صندوق الزبالة بتاع دوره من غير ما يفكر.', 'مي (ساكنة الدور الخامس) — كانت بتستقبل ناس في شقتها في أوقات غريبة وعم حسن كان عارف وبيلمح; أحمد (ساكن الدور الأول) — كان بيجيب كلاب في الشقة وده ممنوع وعم حسن كان بيهدده يشتكيه للمالك', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-07', 'قتل', 'جريمة المصنع', 'المهندس وليد مدير مصنع ملابس في العاشر من رمضان اتلقى ميت في مكتبه في المصنع. اتضرب بحاجة تقيلة على قفاه وبعدين حد حاول يخلي الموضوع يبان حادثة شغل. خمس ناس كانوا في المصنع بعد ساعات الشغل الرسمية.', 5, 2, 'سمير، داليا', 'لقوا المهندس وليد قدام ماكينة الخياطة الكبيرة وراسه فيها جرح كبير; البوليس قال إن الإصابة مش من الماكينة وإن حد ضربه الأول; كاميرات المصنع كانت متعطلة من الساعة ٦ بالليل; لقوا حتة حديد شبه مفتاح ربط كبير فيها أثر دم تحت مكتب وليد; باب المصنع الخلفي كان مفتوح والمفروض يتقفل الساعة ٥', 'سمير المحاسب بتاع المصنع كان عنده صلاحية يقفل الكاميرات من الكمبيوتر بتاعه; داليا مديرة الموارد البشرية كانت في خناقة مع وليد على فصل عمال وهددها يفصلها; لوج الكمبيوتر بيقول إن الكاميرات اتقفلت من جهاز سمير الساعة ٥:٥٥; رسايل بين سمير وداليا على تليجرام بيقولوا "لازم الدفاتر تختفي قبل التفتيش"; وليد كان لسه مكتشف اختلاس في حسابات المصنع وكان هيبلغ البوليس', 'سمير هو اللي اختلس الفلوس من المصنع وداليا كانت بتساعده يزور الأوراق; مفتاح الربط عليه بصمة جزئية مطابقة لسمير; داليا فتحت الباب الخلفي عشان لو احتاجوا يهربوا; شاهد من العمال اللي كان لسه في المصنع شاف داليا خارجة من مكتب وليد الساعة ٧ وشكلها متوترة; سمير حاول يمسح ملفات من الكمبيوتر بتاع المصنع بعد ما وليد مات', 'سمير كان بيختلس من المصنع من سنة وداليا كانت بتساعده يزور الأوراق مقابل نسبة. لما وليد اكتشف وقال هيبلغ البوليس، سمير قفل الكاميرات ونزل مكتب وليد وضربه بمفتاح الربط على قفاه. داليا ساعدته يخلي الموضوع يبان حادثة شغل وفتحت الباب الخلفي كخطة هروب.', 'منى — كانت بتبيع تصميمات المصنع لمنافسين وخايفة وليد يعرف; حسام — كان بيشغل عمال من غير تأمينات وياخد فلوسهم وخايف التفتيش يكشفه; ريم — كانت بتاخد مواد خام من المصنع لمشروعها الخاص', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-08', 'قتل', 'مقتل المطرب', 'المطرب الشعبي حمادة الليثي اتلقى ميت في غرفة الفندق بتاعته في الزمالك بعد حفلة. اتخنق بسلك جيتار. كان فيه خمس ناس معاه في الجناح بتاع الفندق بيحتفلوا بنجاح الألبوم الجديد. حد منهم قتله وهو سكران.', 5, 2, 'رامي، دينا', 'لقوا سلك جيتار ملفوف على رقبة حمادة وهو في السرير; كان فيه إزازات كتير في الأوضة وبواقي أكل; الباب كان مقفول من جوه واللي بلغ عن الجثة كسره; لقوا تليفون حمادة وفيه مكالمة أخيرة مع مديره الساعة ٢ بالليل; في التليفون رسالة من نمرة غريبة بتقول "حفلتك الجاية هتكون الأخيرة"', 'رامي مدير أعمال حمادة كان بياخد نسبة ٥٠٪ وحمادة كان ناوي يفسخ العقد ويمشي لمدير تاني; دينا مطربة صاعدة كانت موجودة وحمادة سرق لحن أغنيتها الجديدة ونزلها باسمه; سلك الجيتار من نفس نوع الجيتار اللي رامي جابه هدية لحمادة في الحفلة; دينا اعترفت إنها هي اللي بعتت رسالة التهديد بس قالت كانت بتتكلم عن إنها هتفضحه مش هتقتله; رامي هو اللي قفل الباب من جوه وادعى إنه كان بره وكسر الباب', 'بصمات رامي على سلك الجيتار واضحة; كاميرا الكوريدور بتوضح إن رامي مخرجش من الجناح خالص — يعني كذب لما قال إنه كسر الباب من بره; دينا اتصورت وهي بتحط حاجة في شرب حمادة — طلعت منوم عشان ينام ويبقى سهل يتخنق; رسايل بين رامي ودينا بيخططوا "لازم الموضوع يبان إنه مات وهو سكران"; عقد سري بين رامي ودينا إنه هيبقى مديرها لو حمادة "خرج من الصورة"', 'رامي كان خايف يخسر دخله لما حمادة قرر يسيبه. دينا كانت عايزة تنتقم من حمادة اللي سرق لحنها. الاتنين اتفقوا — دينا حطت منوم في شرب حمادة وبعد ما نام رامي خنقه بسلك الجيتار. رامي قفل الباب من جوه وبعدين فتحه وكسره عشان يبان إنه لسه داخل.', 'عزت — منتج كان مديون لحمادة وحمادة كان بيضغط عليه يرجع الفلوس; سالي — صحفية كانت بتبتز حمادة بصور قديمة ليه; حسن — عازف كان حمادة طرده من الفرقة وقال عليه كلام وحش في التلفزيون', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-09', 'قتل', 'جريمة المستشفى', 'الدكتور ممدوح استشاري القلب في مستشفى حكومي اتلقى ميت في مكتبه في المستشفى. حد حقنه بإبرة هوا في الوريد وده سبب سكتة قلبية فورية. كان فيه تلات ناس في الدور ده من المستشفى في الشيفت الليلي.', 3, 1, 'منى', 'لقوا سرنجة فاضية مرمية في صندوق النفايات الطبية في الكوريدور; الدكتور ممدوح كان لسه كاتب تقرير طبي عن خطأ طبي حصل في المستشفى وكان هيقدمه للإدارة; باب مكتبه كان مفتوح والنور شغال; كاميرات الدور بتوضح إن تلات ناس بس كانوا موجودين: الممرضة، الطبيب المقيم، وعاملة النضافة; التقرير الطبي اللي كتبه اختفى من على مكتبه', 'منى الممرضة كانت في الشيفت وهي الوحيدة اللي عندها وصول للسرنجات في المخزن; التقرير الطبي كان بيتكلم عن خطأ في عملية عملتها منى وراح فيها مريض; لقوا جوانتي طبي في جيب منى مش طبيعي تحتفظ بيه; سجل دخول المخزن بيقول إن منى فتحته الساعة ١١ بالليل وده مش عادي; زميلة منى قالت إنها كانت متوترة جداً الأيام اللي فاتت وبتتكلم عن إنها "مش هتسيب حد يخرب حياتها"', 'بصمات منى على السرنجة اللي لقوها في صندوق النفايات; التقرير المختفي لقوه ممزق في شنطة منى; كاميرا الكوريدور صورت منى داخلة مكتب الدكتور ممدوح الساعة ١١:٢٠ وخارجة بعد ٥ دقايق; منى كانت هتتحول للنيابة لو التقرير اتقدم وكانت هتتسجن; رسالة على تليفون منى لأختها بتقول "لو التقرير ده اتقدم حياتي خلصت"', 'منى ارتكبت خطأ طبي في عملية ومريض مات بسببها. الدكتور ممدوح اكتشف وكتب تقرير كان هيقدمه للإدارة وده كان هيودي منى السجن. نزلت المخزن وجابت سرنجة ودخلت مكتبه وحقنته بإبرة هوا في الوريد وهو مكانش واخد باله. أخدت التقرير ومزقته وحطته في شنطتها.', 'كريم (الطبيب المقيم) — كان بيزور سجلات المرضى عشان ياخد فلوس تأمين وخايف حد يعرف; أم سعاد (عاملة النضافة) — بتسرق أدوية من المستشفى وتبيعها بره', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-10', 'قتل', 'مقتل صاحب الكافيه', 'باسم صاحب كافيه مشهور في الزمالك اتلقى ميت في الكافيه بعد ما قفل. حد طعنه بسكينة مطبخ في ضهره. كان فيه خمس ناس من اللي بيشتغلوا معاه فضلوا بعد المعاد عشان يحاسبوا آخر الشهر. محدش سمع صريخ لأن المزيكا كانت شغالة.', 5, 2, 'زياد، ريهام', 'لقوا سكينة المطبخ في ضهر باسم وهو قاعد على الكاونتر; الكافيه كان مقفول من جوه والمفتاح كان في جيب باسم; المزيكا كانت شغالة على صوت عالي غير العادي; لقوا دفتر حسابات باسم مفتوح على صفحة فيها أرقام وأسامي; فيه فلوس كاش كتير كانت على الكاونتر واختفت', 'زياد الباريستا الأساسي كان بيسرق من الكاش كل يوم وباسم اكتشف وكان هيبلغ عنه; ريهام المديرة كانت بتعمل فواتير وهمية وبتاخد الفرق; دفتر الحسابات كان مفتوح على صفحة فيها اسم زياد جنب مبلغ ناقص ٥٠ ألف واسم ريهام جنب مبلغ ناقص ٨٠ ألف; زياد هو اللي علّى المزيكا من السماعات بتاعة الكافيه; كاميرا المحل اللي جنبهم صورت ريهام وهي بترمي حاجة في الزبالة بتاعة الشارع', 'الحاجة اللي ريهام رمتها طلعت جوانتي عليه دم باسم; بصمات زياد على يد السكينة; ريهام هي اللي قفلت الكافيه من جوه عشان محدش يدخل; رسالة من زياد لريهام بيقول "مفيش حل تاني — لو باسم بلغ هندخل السجن الاتنين"; كاميرا الكافيه الداخلية — اللي فاكرين إنها مطفية — طلع فيها بطارية احتياطي وصورت زياد ماسك السكينة وريهام واقفة جنبه', 'زياد كان بيسرق من الكاش وريهام كانت بتعمل فواتير وهمية والاتنين سارقين فلوس كتير. لما باسم اكتشف وقرر يبلغ البوليس، زياد وريهام اتفقوا يخلصوا منه. زياد علّى المزيكا وريهام قفلت الباب. زياد طعنه بسكينة المطبخ في ضهره وريهام أخدت الفلوس الكاش من الكاونتر ورمت الجوانتي بره.', 'عمر — كان بيبيع حشيش للزباين من الباب الخلفي للكافيه وباسم مكانش يعرف; سلمى — كانت بتستخدم واي فاي الكافيه في عمليات نصب أونلاين; تامر — كان بيجيب خامات رخيصة وبيقول لباسم إنها غالية وياخد الفرق', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-01'), 'كريم', 1, 'رجل أعمال في الأربعينات، صاحب شركة استيراد وتصدير. كان صاحب عم سيد من زمان وبينهم شراكات تجارية كتير. معروف إنه بيحب الفلوس وبيعمل أي حاجة عشان مصلحته.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-01'), 'هاجر', 2, 'مهندسة معمارية في التلاتينات، جارة عم سيد في المرسى وبتأجر مركب جنبه. هادية ومش بتتكلم كتير بس بتراقب كل حاجة حواليها. كانت بتساعد عم سيد في حاجات كتير.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-01'), 'محمد', 3, 'تاجر سمك في الخمسينات، بيشتغل على النيل من صغره. عم سيد كان بيأجرله المركب أحياناً. صوته عالي ودايماً متوتر بس الناس بتحبه.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-01'), 'نور', 4, 'مصورة فوتوغرافية في التلاتينات، كانت بتصور على المركب لمشروع فني. شخصية رومانسية وبتحب المغامرة. عم سيد كان معجب بيها وبيدعوها كتير.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-01'), 'أحمد', 5, 'ميكانيكي مراكب في الأربعينات، كان بيصلح مركب عم سيد من سنين. اتطرد من شغله قريب وزعلان. بيشرب كتير ومزاجه متقلب.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-02'), 'سارة', 1, 'صيدلانية في الخامسة والتلاتين، ذكية وشيك وبتحب الحياة الراقية. صاحبة طارق باشا من زمان وبتيجي كل عزوماته. الناس بتقول إنها طموحة أوي وبتعمل أي حاجة عشان توصل.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-02'), 'عمرو', 2, 'مستثمر عقاري في الأربعينات، شريك طارق باشا في مشاريع كتير. أنيق وبيتكلم حلو بس الناس بتقول إنه ماكر وبيحسب كل حاجة.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-02'), 'فاطمة', 3, 'طليقة طارق باشا في الأربعينات، ست قوية ومش بتخاف من حد. الطلاق كان صعب وفيه قضايا لسه في المحاكم. بتكره طارق بس بتحب فلوسه.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-02'), 'مصطفى', 4, 'راجل أعمال في الخمسينات، صاحب طارق من أيام الجامعة. بيحب القمار وخسران فلوس كتير. طارق كان بيساعده بس بقى رافض.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-02'), 'شريف', 5, 'راجل في التلاتينات، كان بيشتغل سواق عند طارق وساب الشغل في ظروف غامضة. عنده سوابق ومعروف إنه عنيف لما يتعصب.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-03'), 'ياسمين', 1, 'ممثلة مسرحية في التلاتينات، جميلة وموهوبة بس حظها في الحياة صعب. بتشتغل مع أبو طارق من ٣ سنين وهو اللي عملها نجمة. الناس بتقول إنها بتكرهه بس مش بتعرف تسيبه.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-03'), 'مصطفى', 2, 'فني إضاءة في الأربعينات، بيشتغل في المسرح من ١٥ سنة. هادي ومش بيتكلم كتير بس بيعرف كل حاجة عن المسرح وكل الأسرار. أبو طارق كان بيعامله وحش.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-03'), 'هدى', 3, 'محاسبة المسرح في الخمسينات، ست طيبة بس بتحب الفلوس. بتشتغل في المسرح من ١٠ سنين وبتعرف كل الحسابات.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-03'), 'عمرو', 4, 'ممثل شاب في العشرينات، طموح وعايز يبقى نجم. بيحسد كل الناس اللي أحسن منه وبيعمل أي حاجة عشان ياخد فرصة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-03'), 'كريم', 5, 'ممثل في التلاتينات، كان المفروض ياخد دور البطولة بس أبو طارق اختار حد تاني. زعلان ومكسور وبيقول إن أبو طارق ظلمه.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-04'), 'نور', 1, 'ممرضة في التلاتينات، بتشتغل مع الدكتور حازم من ٥ سنين. شاطرة في شغلها وكل المرضى بيحبوها. بس الفترة الأخيرة كانت متوترة ومش في حالها.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-04'), 'أحمد', 2, 'المريض الأخير، راجل في الخمسينات بيجي العيادة كتير. محدش يعرف عنه حاجة كتير وبيدفع كاش دايماً. هادي بس بيبان عليه التوتر.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-04'), 'باسم', 3, 'سكيورتي العمارة في الأربعينات، راجل بسيط وبيحب يساعد الناس. بيشتغل شيفتات ليلي ودايماً تعبان. عم حسن كان صاحبه.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-05'), 'فاطمة', 1, 'مرات الحاج عبدالله وتانية، في الأربعينات. ست بيتها بس ذكية وبتعرف تتعامل. الناس بتقول إنها اتجوزت الحاج عشان فلوسه مش عشان بتحبه.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-05'), 'طارق', 2, 'ابن الحاج عبدالله من مراته الأولى، في التلاتينات. بيشتغل في شركة بس مش ناجح ومديون. علاقته بأبوه وحشة وبيتخانقوا على الفلوس دايماً.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-05'), 'مي', 3, 'مرات طارق، في التلاتينات. جميلة وبتحب الحياة. بتحاول تبان إن كل حاجة تمام بس من جوه تعبانة. الحاج عبدالله مكانش بيحبها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-05'), 'حسن', 4, 'ابن أخو الحاج عبدالله، في العشرينات. بيشتغل معاه في المحل. شاب لطيف بس بيحب الفلوس أوي وعايز يكبر بسرعة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-05'), 'ليلى', 5, 'بنت الحاج عبدالله، في العشرينات. بتدرس في الجامعة وبتحب أبوها بس زعلانة إنه بيفرق في المعاملة بينها وبين إخواتها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-06'), 'شريف', 1, 'نجار في الأربعينات ساكن في الدور التالت. راجل شغله كتير ومش بيتكلم مع حد في العمارة. بينه وبين عم حسن مشاكل قديمة ومحدش يعرف السبب بالظبط.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-06'), 'مي', 2, 'ست في التلاتينات ساكنة في الدور الخامس لوحدها. بتشتغل من البيت ومش بتنزل كتير. الجيران بيقولوا إن ناس غريبة بتيجي لها بالليل وبتمشي.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-06'), 'أحمد', 3, 'شاب في العشرينات ساكن في الدور الأول مع كلبه. طيب وبيحب يساعد الناس بس عم حسن كان دايماً بيزعقله بسبب الكلب.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-07'), 'سمير', 1, 'محاسب المصنع في الخمسينات، بيشتغل هنا من ١٠ سنين. هادي ومنظم وبيعرف كل حاجة عن فلوس المصنع. الناس بتثق فيه لأنه بيبان أمين.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-07'), 'داليا', 2, 'مديرة الموارد البشرية في التلاتينات، ذكية وطموحة. بتتعامل مع كل العمال والأوراق. كانت في خناقة مع المهندس وليد على فصل عمال.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-07'), 'منى', 3, 'مصممة أزياء في المصنع في التلاتينات، موهوبة بس مش بتاخد حقها. بتشتغل ساعات كتير وبتحلم تفتح مشروعها الخاص.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-07'), 'حسام', 4, 'مشرف العمال في الأربعينات، راجل قوي وصوته عالي. بيتعامل مع العمال بشكل مباشر وبيعرف كل حاجة بتحصل في المصنع.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-07'), 'ريم', 5, 'مهندسة إنتاج في العشرينات، لسه جديدة في المصنع من ٦ شهور. شاطرة بس الناس مش بتثق فيها لأنها جديدة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-08'), 'رامي', 1, 'مدير أعمال حمادة الليثي من ٥ سنين، في الأربعينات. ذكي وبيفهم في الفن والفلوس. حمادة كان بيثق فيه ثقة عمياء بس الناس بتقول إنه جشع.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-08'), 'دينا', 2, 'مطربة صاعدة في العشرينات، موهوبة وجميلة. كانت بتحاول تنجح من سنين. حمادة ساعدها في الأول بس بعدين خدعها وسرق شغلها.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-08'), 'عزت', 3, 'منتج موسيقي في الخمسينات، بيشتغل في المجال من زمان. مديون لحمادة بفلوس كتير وحمادة كان بيضغط عليه يسدد.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-08'), 'سالي', 4, 'صحفية فنية في التلاتينات، بتعرف أسرار كل الفنانين. بتحب تجمع معلومات وبتستخدمها. حمادة كان خايف منها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-08'), 'حسن', 5, 'عازف جيتار في التلاتينات، كان في فرقة حمادة من البداية. حمادة طرده فجأة وقال عليه كلام وحش في التلفزيون. مجروح ومكسور بس مش عنيف.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-09'), 'منى', 1, 'ممرضة في الأربعينات، بتشتغل في المستشفى من ١٥ سنة. محترمة ومعروفة إنها شاطرة. بس الفترة الأخيرة كانت متوترة ومش بتنام كويس.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-09'), 'كريم', 2, 'طبيب مقيم في التلاتينات، لسه جديد في المستشفى من سنة. شاطر بس بيبان عليه إنه محتاج فلوس دايماً. بيشتغل شيفتات كتير.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-09'), 'أم سعاد', 3, 'عاملة نضافة في الستينات، بتشتغل في المستشفى من ٢٠ سنة. ست غلبانة وعندها عيال ومحتاجة فلوس. الكل بيحبها بس محدش بيعرف حاجة عنها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-10'), 'زياد', 1, 'باريستا في العشرينات، بيشتغل في الكافيه من ٣ سنين. شاب ظريف والزباين بيحبوه. باسم كان بيعامله كويس بس زياد كان عايز أكتر.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-10'), 'ريهام', 2, 'مديرة الكافيه في التلاتينات، بتشتغل هنا من سنتين. منظمة وشاطرة وباسم كان بيثق فيها. الناس بتقول إنها بتحب السيطرة وبتحب الفلوس.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-10'), 'عمر', 3, 'ويتر في العشرينات، شاب من الصعيد جاي القاهرة يشتغل. طيب بس بيعرف ناس غلط وبيتورط في حاجات مش كويسة من غير ما يقصد.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-10'), 'سلمى', 4, 'بتشتغل كاشير في الكافيه في العشرينات، بنت ذكية وبتفهم في التكنولوجيا. هادية ومش بتتكلم كتير بس دايماً قاعدة على اللابتوب بتاعها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'M-10'), 'تامر', 5, 'مسؤول المشتريات في الأربعينات، بيجيب كل حاجة للكافيه. راجل عملي ومش بيحب الدراما بس الناس بتقول إنه بيحب يكسب من أي حاجة.', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-01', 'سرقة', 'خزنة شركة المعادي', 'شركة مقاولات في المعادي، الصبح لما المدير فتح الخزنة لقاها فاضية — مليون ونص جنيه اتسرقوا بالليل. الكاميرات كانت فاصلة من ١٢ لـ٣ الفجر ومفيش أي كسر في الأبواب. الشرطة لقت إن اللي سرق كان عارف الكود بتاع الخزنة والمكان بالظبط.', 5, 2, 'شريف، هدى', 'الكاميرات اتفصلت من جوه مش من بره — حد عارف نظام السيكيوريتي; لقوا أثر شاي وسجاير في مكتب المدير مع إن محدش المفروض كان موجود; باب الشركة اتفتح بالمفتاح الأصلي مش بالكسر; الخزنة اتفتحت من أول محاولة — يعني حد عارف الكود; لقوا شنطة بلاستيك سودا فيها بقايا فلوس في الزبالة بتاعت الشارع', 'شريف كان عنده نسخة من مفتاح الشركة عملها من سنة وما رجعهاش; هدى كانت بتسأل كتير عن نظام الكاميرات وازاي بيتقفل; فيه تحويل بنكي غريب في حساب هدى قبل السرقة بيومين — وديعة ١٠٠ ألف; شريف كان بيشتغل لوحده لحد متأخر قبل السرقة بيوم وقال إنه بيراجع ملفات; لقوا على موبايل شريف رسالة لهدى بيقول فيها "الموضوع اتظبط خلاص"', 'الكود بتاع الخزنة كان متغير قبلها بأسبوع — وهدى هي اللي كانت موجودة لما المدير غيّره; شريف كان شغال في شركة سيكيوريتي قبل كده وعارف يفصل أي نظام كاميرات; لقوا في عربية شريف كيس فيه ٢٠٠ ألف جنيه مخبيين تحت الكرسي; هدى حجزت تذكرة سفر للغردقة بعد السرقة بيومين; شهادة حارس العمارة إنه شاف شريف وهدى سوا الساعة ١ بالليل قريب من الشركة', 'شريف فصل الكاميرات عشان كان شغال سيكيوريتي قبل كده وعارف النظام، وهدى حفظت الكود الجديد لما المدير غيّره قدامها. الاتنين اتفقوا ودخلوا بالمفتاح بتاع شريف الساعة ١ بالليل، فتحوا الخزنة وقسموا الفلوس بينهم.', 'أحمد — المحاسب — كان محتاج فلوس عشان عملية لأمه وكان طلب سلفة المدير رفضها; كريم — الأوفيس بوي — كان بيسهر في الشركة ساعات عشان مفيش عنده مكان تاني يروحه; نور — السكرتيرة — عندها ديون كتير ومحدش عارف وكانت بتسحب فلوس من حسابها كتير الفترة دي', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-01'), 'شريف', 1, 'مسؤول الصيانة في الشركة من ٣ سنين، هو اللي بيتعامل مع أي عطل في المكان ومعاه مفاتيح كل الأدوار', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-01'), 'هدى', 2, 'مديرة الحسابات الجديدة، لسه شغالة من ٦ شهور بس المدير واثق فيها جداً وبيديها صلاحيات كتير', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-01'), 'أحمد', 3, 'المحاسب القديم في الشركة من ١٠ سنين، بيعرف كل حاجة عن الفلوس والحسابات', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-01'), 'كريم', 4, 'الأوفيس بوي، شاب غلبان بيعمل الشاي والقهوة وبيوصل الأوراق بين الأدوار', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-01'), 'نور', 5, 'السكرتيرة بتاعت المدير، بتنظم مواعيده وعندها مفتاح مكتبه', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-02', 'سرقة', 'دهب الفرح في طنطا', 'فرح كبير في طنطا، العروسة لبست الشبكة — دهب بحوالي ٤٠٠ ألف جنيه — وبعد ما الفرح خلص ورجعوا البيت، العروسة فتحت الشنطة لقت الدهب مش موجود. الشبكة كانت في شنطة ساتان حمرا في أوضة العروسة في الصالة. النور اتقطع مرتين وقت الفرح والناس كانت كتير.', 5, 2, 'فاطمة، عمرو', 'الشنطة الحمرا لقوها ورا الكنبة فاضية — حد فتحها بهدوء; النور اتقطع مرتين: مرة ١٠ دقايق ومرة ٥ دقايق — والتانية كانت وقت السرقة; واحدة من المعازيم شافت حد داخل أوضة العروسة وقت ما النور كان فاصل; لقوا علبة دهب فاضية جوه كيس زبالة في المطبخ; واحد من الجيران قال إنه شاف عربية مشيت بسرعة بعد الفرح ما خلص', 'فاطمة — صاحبة العروسة — كانت هي اللي ماسكة مفتاح أوضة العروسة; عمرو — ابن عم العريس — هو اللي كان مسؤول عن الكهربا في الصالة; فاطمة اتصورت وهي لابسة أساور شبه أساور الشبكة بعد الفرح بيوم; عمرو اشترى موبايل جديد آيفون بعد الفرح بـ٣ أيام; لقوا في شنطة فاطمة اللي سابتها في الصالة مفك صغير ومنديل', 'عمرو هو اللي قطع النور عمداً — لقوا في موبايله تايمر مظبوط على نفس أوقات القطع; فاطمة اتصورت بأساور طلعت هي هي أساور الشبكة — لما كبّروا الصور طابقوها; لقوا في عربية عمرو اللي كانت واقفة ورا الصالة بقايا قماش ساتان أحمر; فاطمة عندها حساب على أوليكس كانت عارضة فيه دهب للبيع بعد الفرح بيومين; شهادة الحلواني إنه شاف فاطمة وعمرو بيتكلموا في السر قبل ما النور يقطع', 'عمرو قطع الكهربا عن الصالة عمداً مرتين — المرة التانية فاطمة دخلت أوضة العروسة وأخدت الدهب من الشنطة وطلعت. عمرو استناها برا بالعربية ومشيوا بيه. بعدها فاطمة عرضت الدهب للبيع أونلاين وقسموا الفلوس بينهم.', 'سارة — أخت العروسة — كانت متخانقة مع أختها على الميراث وناس كتير سمعتها بتقول "دي مش مستاهلة الدهب ده"; ريم — قريبة العريس — عندها مشاكل مادية ومحدش عارف وكانت بتلف في الصالة كتير وقت الفرح; مصطفى — صاحب العريس — اتشاف وهو بيصور أوضة العروسة بموبايله من بره', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-02'), 'فاطمة', 1, 'صاحبة العروسة المقربة، كانت بتساعدها في تجهيز الفرح ومعاها مفتاح أوضة العروسة في الصالة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-02'), 'عمرو', 2, 'ابن عم العريس، كان مسؤول عن الصوت والكهربا في الصالة عشان بيشتغل كهربائي', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-02'), 'سارة', 3, 'أخت العروسة الكبيرة، كانت بتساعد في تنظيم الفرح وبتستقبل المعازيم', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-02'), 'ريم', 4, 'قريبة العريس من ناحية أمه، جات الفرح من الإسكندرية وكانت قاعدة جنب أوضة العروسة', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-02'), 'مصطفى', 5, 'صاحب العريس من الجامعة، كان المصور الرسمي للفرح بموبايله', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-03', 'سرقة', 'محل خان الخليلي', 'عم حسن صاحب محل فضة وأنتيكات في خان الخليلي، الصبح فتح المحل لقى الفاترينة الرئيسية مكسورة وأنتيكات بقيمة ٢٠٠ ألف جنيه اختفت. المحل اتقفل بالترباس العادي ومفيش أي علامة كسر على الباب. عم حسن قال إن ٣ أشخاص بس معاهم مفتاح المحل.', 3, 1, 'كريم', 'الفاترينة اتكسرت من ورا مش من قدام — يعني حد عارف التصميم; لقوا بصمات على الفاترينة من جوه — حد كان لابس جوانتيات بس قلعها عشان يفتح القفل; باب المحل اتفتح بالمفتاح وبعدين اتقفل تاني بعد السرقة; كاميرا محل جنبه صورت شبح حد ماشي الساعة ٣ الفجر; عم حسن قال إن القطع اللي اتسرقت كلها من نفس الرف — يعني حد عارف الأغلى فين', 'كريم اشترى شنطة سفر كبيرة من أمازون قبل السرقة بأسبوع; لقوا رسايل على موبايل كريم بيسأل فيها عن تاجر أنتيكات في الحسين بيشتري من غير فواتير; مفتاح كريم كان عليه خدوش جديدة يعني اتنسخ قريب; كريم كان بيقفل المحل لوحده آخر ٣ أيام عشان عم حسن كان تعبان; الكاميرا بتاعت محل الشاي اللي قصاد صورت حد شبه كريم الساعة ٢ ونص بالليل', 'لقوا عند تاجر الأنتيكات في الحسين ٣ قطع من المسروقات وقال إن كريم باعهمله; كريم كان عنده ديون لناس وحشة وكان لازم يدفع قبل آخر الأسبوع; بصمة كريم طلعت متطابقة مع البصمة اللي على الفاترينة من جوه; كريم غيّر رقم موبايله بعد السرقة بيوم; عم حسن فاكر إن كريم كان بيسأله كتير عن أسعار القطع الغالية', 'كريم كان عارف المحل كويس عشان بيشتغل فيه من ٤ سنين. نسخ المفتاح وراح الساعة ٣ الفجر، فتح الباب وكسر الفاترينة من ورا عشان يبان إن حد من بره عملها. أخد أغلى القطع في شنطة السفر اللي اشتراها وباع جزء منهم لتاجر في الحسين عشان يسدد ديونه.', 'عم حسن — صاحب المحل — كان عليه ضرائب متأخرة وناس شاكة إنه ممكن يكون عمل السرقة عشان التأمين; هاجر — بنت عم حسن — كانت محتاجة فلوس لمصاريف الجامعة وكانت بتيجي المحل كتير الفترة الأخيرة', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-03'), 'كريم', 1, 'الصنايعي اللي شغال مع عم حسن في المحل من ٤ سنين، بيعرف كل حاجة عن البضاعة ومعاه مفتاح', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-03'), 'عم حسن', 2, 'صاحب المحل، راجل كبير عنده ٦٠ سنة ومعروف في خان الخليلي من ٣٠ سنة', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-03'), 'هاجر', 3, 'بنت عم حسن، طالبة في الجامعة وساعات بتيجي تساعد أبوها في المحل', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-04', 'سرقة', 'شقة الدقي', 'مدام سميرة رجعت من السفر لقت شقتها في الدقي اتسرقت — لابتوبين وتلفزيون وفلوس كانت في الدولاب — حوالي ١٥٠ ألف جنيه. الباب كان مقفول عادي ومفيش كسر. مدام سميرة سابت مفتاح عند الجارة ومفتاح تاني عند الشغالة. السرقة حصلت في أسبوع سفرها.', 3, 1, 'مي', 'الباب اتفتح بمفتاح مش بالكسر; لقوا إن الحرامي كان عارف مكان الفلوس بالظبط — الدولاب اللي في أوضة النوم; مفيش أي بصمات غريبة — يعني اللي دخل كان لابس جوانتيات أو حد معروف في الشقة; الجيران مشافوش حد غريب طول الأسبوع; كاميرا العمارة بتاعت المدخل كانت مش شغالة من شهر', 'مي — الشغالة — كانت عارفة إن مدام سميرة مسافرة ومعاها مفتاح; مي طلبت أجازة فجأة بعد ما مدام سميرة رجعت من السفر; لقوا إن مي دخلت الشقة ٣ مرات في أسبوع السفر مش مرة واحدة زي ما مدام سميرة طلبت; جوز مي اشترى موتوسيكل جديد الأسبوع اللي بعد السرقة; لقوا شنطة بلاستيك في بيت مي فيها كابل شاحن لابتوب نفس نوع بتاع مدام سميرة', 'اللابتوب الواحد لقوه عند تاجر مستعمل في العتبة وقال إن ست وصفها زي مي باعتهوله; مي بصماتها مطابقة لبصمات موجودة جوه الدولاب في أوضة النوم; مي اتصلت بأختها وقالتلها "حصلت على فلوس كويسة" قبل ما مدام سميرة ترجع; مي مكانش عندها حساب بنكي بس فجأة فتحت واحد وحطت فيه ٤٠ ألف; جارة مي شافتها شايلة شنط تقيلة يوم الأربعا بالليل', 'مي كانت بتدخل الشقة بالمفتاح اللي عندها. دخلت ٣ مرات — المرة الأولى شافت الفلوس في الدولاب، التانية جابت جوزها وشالوا اللابتوبات والتلفزيون في شنط، والتالتة أخدت الفلوس ومسحت أي أثر. باعت الأجهزة في العتبة وقسمت الفلوس مع جوزها.', 'منى — الجارة — عندها مفتاح الشقة كمان وكانت محتاجة فلوس عشان جوزها مريض; أبو حسين — البواب — بيشرب حشيش وبينام بالليل وناس بتقول إنه بيسيب العمارة مفتوحة', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-04'), 'مي', 1, 'الشغالة بتاعت مدام سميرة من سنتين، بتيجي ٣ أيام في الأسبوع ومعاها مفتاح الشقة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-04'), 'منى', 2, 'جارة مدام سميرة اللي في نفس الدور، ست طيبة بس ظروفها صعبة ومعاها المفتاح التاني', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-04'), 'أبو حسين', 3, 'بواب العمارة من ١٥ سنة، بيعرف مين بيدخل ومين بيطلع بس مش دايماً صاحي', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-05', 'سرقة', 'مخزن العاشر من رمضان', 'مخزن أجهزة كهربائية في المنطقة الصناعية في العاشر من رمضان اتسرق منه بضاعة بمليونين جنيه. السرقة حصلت يوم الجمعة بالليل لما المنطقة بتكون فاضية. الحراسة لقت باب المخزن مفتوح الصبح والبضاعة ناقصة. مفيش كسر — الباب اتفتح بالكود والمفتاح.', 5, 2, 'محمد، سارة', 'باب المخزن اتفتح بالكود الصح من أول مرة; لقوا آثار عجل نقل كبير عند باب المخزن — يعني حد جاب عربية نقل; البضاعة المسروقة كلها من نوع واحد — الشاشات الغالية بس; الحارس بيقول إنه كان صاحي بس ما شافش حاجة غريبة; كاميرا المخزن اللي جنبه صورت عربية نقل بيضا من غير لوح الساعة ٢ بالليل', 'محمد — مدير المخزن — كان يوم الجمعة في الإسكندرية بس رجع القاهرة بالليل; سارة — المحاسبة — كانت عارفة إن البضاعة الجديدة وصلت يوم الخميس; محمد طلب من الحراسة إنهم ما يشتغلوش أوفر تايم يوم الجمعة عشان "مفيش حاجة مهمة"; لقوا رسالة من سارة لمحمد بتقول "البضاعة الجديدة بكام بالظبط؟" قبل السرقة بيومين; سارة كانت عارفة كود المخزن عشان بتعمل الجرد كل شهر', 'محمد أجّر عربية نقل بيضا يوم الخميس ورجّعها السبت الصبح; سارة حوّلت ١٥٠ ألف جنيه لحساب مش باسمها يوم الحد; لقوا في بيت محمد فاتورة من شركة نقل بتاريخ يوم الجمعة; سارة غيّرت الباسورد بتاع نظام الجرد يوم السبت الصبح; شهادة حارس المنطقة إنه شاف عربية نقل بيضا ومعاها واحد ست وراجل', 'محمد عرف إن شحنة شاشات غالية وصلت، اتفق مع سارة اللي عندها الكود. يوم الجمعة بالليل محمد أجّر عربية نقل، سارة فتحت المخزن بالكود والمفتاح الاحتياطي، شحنوا الشاشات وباعوها لتاجر في بورسعيد. سارة غيّرت بيانات الجرد عشان تأخّر اكتشاف النقص.', 'أبو سمير — الحارس — بينام في الشيفت وكذب إنه كان صاحي، وكان خايف يتفصل; وائل — سواق النقل في الشركة — كان طلب زيادة مرتب ومرفوضة وبيقول إنه هيعمل حاجة; حسام — عامل المخزن — كان بيسرق حاجات صغيرة قبل كده واتمسك مرة', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-05'), 'محمد', 1, 'مدير المخزن من ٥ سنين، مسؤول عن كل البضاعة ومعاه مفتاح وكود المخزن', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-05'), 'سارة', 2, 'محاسبة الشركة، بتعمل الجرد الشهري ومعاها كود المخزن والنظام', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-05'), 'أبو سمير', 3, 'حارس المخزن الليلي، راجل كبير بيشتغل من ٨ سنين ومعروف إنه بينعس', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-05'), 'وائل', 4, 'سواق النقل بتاع الشركة، بيعرف طرق المنطقة الصناعية كلها', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-05'), 'حسام', 5, 'عامل المخزن، بيرص البضاعة وبيعرف مكان كل حاجة', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-06', 'سرقة', 'خزنة نادي مصر الجديدة', 'نادي رياضي في مصر الجديدة، خزنة إدارة النادي فيها اشتراكات الأعضاء — ٣٥٠ ألف جنيه — اتسرقت يوم السبت بالليل بعد ما النادي قفل. الكاميرات كانت شغالة بس التسجيل اتمسح من الساعة ١٠ بالليل للساعة ٥ الصبح. المفتاح الرئيسي للإدارة كان في مكانه.', 5, 2, 'طارق، ياسمين', 'التسجيل اتمسح من الكمبيوتر اللي في أوضة الحراسة — حد عارف الباسورد; الخزنة اتفتحت بالأرقام مش بالكسر; لقوا إن باب الإدارة اتفتح بمفتاح تاني مش المفتاح الأصلي; جوانتيات بلاستيك شفافة في سلة الزبالة بتاعت الإدارة; لقوا أثر جزمة رياضية على السجادة في الإدارة', 'طارق — مدير الاشتراكات — كان آخر واحد مشي من النادي يوم السبت الساعة ١٠; ياسمين — بنت رئيس النادي — كانت في النادي لحد الساعة ٩ ونص وقالت إنها مشيت; طارق معاه مفتاح احتياطي للإدارة محدش عارف بيه; ياسمين كانت عارفة باسورد كمبيوتر الحراسة عشان أبوها قالهولها; لقوا عند طارق في الدرج بتاعه ورقة مكتوب عليها أرقام — طلعت كود الخزنة', 'ياسمين رجعت النادي الساعة ١١ بالليل — كاميرا الشارع صورتها; طارق كان لسه في النادي الساعة ١١ مع إنه قال إنه مشي الساعة ١٠; ياسمين مسحت التسجيل من الكمبيوتر عشان عارفة الباسورد; لقوا الفلوس ناقصة ٣٥٠ ألف بالظبط — نفس رقم الاشتراكات اللي طارق كان بيجمعها; موبايل طارق فيه رسالة لياسمين "هتيجي الساعة كام؟" يوم السبت الساعة ٩', 'طارق فضل في النادي بعد ما الكل مشي وفتح الإدارة بالمفتاح الاحتياطي وفتح الخزنة بالكود اللي كان كاتبه. ياسمين رجعت الساعة ١١ ومسحت تسجيل الكاميرات من الكمبيوتر. أخدوا الفلوس وطارق خبّاهم في شنطة الجيم بتاعته. ياسمين كانت محتاجة فلوس عشان مشروعها الخاص وطارق كان عليه ديون قمار.', 'مازن — الحارس — كان نايم وقت السرقة وكذب إنه كان صاحي عشان خايف يتفصل; جنى — موظفة الاستقبال — كانت بتاخد فلوس من الاشتراكات وبتأجل تسليمها; أمير — المدرب — كان بيدخل الإدارة من غير إذن عشان ياخد مفاتيح الملاعب', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-06'), 'طارق', 1, 'مدير الاشتراكات في النادي من ٣ سنين، بيجمع الفلوس من الأعضاء ومسؤول عن الخزنة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-06'), 'ياسمين', 2, 'بنت رئيس النادي، بتيجي كل يوم وعارفة كل حاجة عن النادي ومعاها صلاحيات كتير', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-06'), 'مازن', 3, 'حارس النادي الليلي، راجل هادي بيشتغل من ٥ سنين', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-06'), 'جنى', 4, 'موظفة الاستقبال، بتتعامل مع الأعضاء وبتاخد منهم الفلوس', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-06'), 'أمير', 5, 'مدرب اللياقة البدنية في النادي، بيعرف المكان كويس وبيفضل لحد بالليل', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-07', 'سرقة', 'ورشة شبرا الخيمة', 'ورشة نجارة في شبرا الخيمة، عم صابر صاحب الورشة فتح الصبح لقى ماكينة القص الكبيرة مش موجودة ومعدات كهربائية بقيمة ١٨٠ ألف جنيه اختفت. الباب كان مفتوح ومفيش كسر. عم صابر بيقول إن المفتاح كان معاه بس في نسخة تانية عند الصنايعي بتاعه.', 3, 1, 'رامي', 'الباب اتفتح بمفتاح وبعدين اتساب مفتوح — يعني حد كان مستعجل; آثار عجل تقيل على الأرض — حد جاب عربية نقل كبيرة; السرقة حصلت بين ١٢ بالليل و٥ الصبح حسب كلام الجيران; المعدات المسروقة كلها كبيرة ومحتاجة ٣-٤ أشخاص يشيلوها; لقوا سيجارة مطفية عند الباب من نوع كليوباترا', 'رامي — الصنايعي — معاه النسخة التانية من المفتاح; رامي اتصل بسواق نقل يوم الخميس وسأله عن أسعار نقل معدات تقيلة; لقوا إن رامي كان بيدور على ورش بتشتري معدات مستعملة الفترة اللي فاتت; رامي كان متخانق مع عم صابر على فلوس متأخرة وبيقول "حقي هاخده"; الجيران سمعوا صوت عربية نقل الساعة ٢ بالليل', 'سواق النقل اعترف إن رامي اتصل بيه وطلبه الساعة ١ بالليل ونقلوا حاجات من ورشة; لقوا الماكينة الكبيرة في ورشة تانية في قليوب — صاحبها قال إن رامي باعهاله; رامي بصمته على الباب من جوه في مكان مش المعتاد; رامي بيدخن كليوباترا — نفس نوع السيجارة اللي لقوها; رامي قال إنه كان في بيته نايم بس مراته قالت إنه خرج الساعة ١٢', 'رامي كان زعلان من عم صابر عشان مأخرش عليه فلوسه. اتفق مع سواق نقل يعرفه، فتح الورشة بالمفتاح اللي عنده الساعة ١ بالليل، جابوا ٣ عمال وشالوا الماكينة والمعدات. باع كل حاجة لورشة في قليوب وأخد الفلوس. ساب الباب مفتوح عشان كان مستعجل يمشي.', 'عم صابر — صاحب الورشة — كان عنده تأمين على المعدات وناس بتقول ممكن يكون عاوز فلوس التأمين; نادية — مرات عم صابر — كانت عارفة مكان المفتاح الاحتياطي وكانت محتاجة فلوس لعلاج ابنها', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-07'), 'رامي', 1, 'الصنايعي الأساسي في الورشة من ٦ سنين، بيعرف كل المعدات ومعاه مفتاح الورشة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-07'), 'عم صابر', 2, 'صاحب الورشة، راجل في الخمسينات ومعروف في المنطقة وعنده عمال كتير', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-07'), 'نادية', 3, 'مرات عم صابر، بتيجي الورشة ساعات وبتساعد في الحسابات', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-08', 'سرقة', 'بنك وسط البلد', 'فرع بنك في وسط البلد، الصبح لما المدير فتح لقى الخزنة الكبيرة مفتوحة وناقص منها ٣ مليون جنيه كاش. الكاميرات كانت شغالة بس لقوا إن حد حط لوب — يعني التسجيل بيعيد نفسه. مفيش كسر في أي باب ومفيش إنذار اتشغل. السرقة محتاجة حد عارف نظام الأمان كويس.', 5, 2, 'خالد، دينا', 'الكاميرات كان عليها لوب — حد عارف النظام حطه بشكل احترافي; الخزنة اتفتحت بالكود مش بالكسر — والكود بيتغير كل أسبوع; الإنذار كان مفصول من السيرفر مش من الجهاز نفسه; لقوا جوانتيات طبية في سلة الزبالة في الحمام; باب البنك الخلفي اتفتح بكارت أمان — والكارت ده مع ٣ أشخاص بس', 'خالد — مسؤول الأمن — هو اللي بيغير كود الخزنة كل أسبوع; دينا — مبرمجة نظام الكاميرات — كانت في البنك يوم الخميس بتعمل صيانة; خالد كان يوم السبت بالليل في البنك لحد الساعة ١١ — قال إنه كان بيراجع النظام; لقوا إن دينا دخلت على سيرفر الكاميرات عن بعد يوم الجمعة الساعة ١ بالليل; كارت الباب الخلفي بتاع خالد اتستعمل الساعة ١٢ بالليل يوم الجمعة', 'دينا حطت اللوب على الكاميرات من البيت — لقوا الـIP بتاعها; خالد كان عارف الكود الجديد عشان هو اللي غيّره يوم الخميس; لقوا في شنطة دينا فلاشة عليها كود اللوب بتاع الكاميرات; خالد اشترى شقة جديدة في الشروق بعد السرقة بأسبوعين; فيه رسايل واتساب بين خالد ودينا بيتكلموا عن "المشروع" اللي هيغير حياتهم', 'خالد استخدم كارت الباب الخلفي ودخل البنك الساعة ١٢ بالليل يوم الجمعة. دينا كانت في بيتها بتتحكم في الكاميرات وحطت اللوب وفصلت الإنذار من السيرفر. خالد فتح الخزنة بالكود اللي هو غيّره بنفسه وأخد ٣ مليون في شنطتين. الاتنين خبّوا الفلوس في شقة دينا وبدأوا يصرفوا ببطء.', 'عادل — مدير الفرع — كان عنده مشاكل مالية وبياخد قروض كتير; سمر — الكاشيرة — اتمسكت قبل كده بخطأ في الحسابات وناس شاكة فيها; حسن — الحارس — كان بينام في الشيفت وكذب في شهادته', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-08'), 'خالد', 1, 'مسؤول الأمن في البنك من ٧ سنين، معاه كل المفاتيح والأكواد ومسؤول عن الخزنة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-08'), 'دينا', 2, 'مبرمجة نظام الكاميرات والأمان، بتيجي البنك كل أسبوع تعمل صيانة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-08'), 'عادل', 3, 'مدير الفرع، مسؤول عن كل حاجة في البنك ومعاه كارت الباب الخلفي', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-08'), 'سمر', 4, 'الكاشيرة، شغالة في البنك من ٤ سنين وبتتعامل مع الفلوس كل يوم', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-08'), 'حسن', 5, 'حارس البنك الليلي، راجل كبير هادي ومعروف إنه بينعس في الشيفت', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-09', 'سرقة', 'معرض التجمع', 'معرض موبايلات في التجمع الخامس، صاحبه أحمد فتح الصبح لقى ٤٠ موبايل آيفون اختفوا من الفاترينة — بقيمة ٨٠٠ ألف جنيه. الشاتر كان مقفول والكاميرا الداخلية اتقطع سلكها. أحمد بيقول إن مفتاح الشاتر مع ٣ أشخاص بس: هو والمدير والعامل.', 3, 1, 'تامر', 'سلك الكاميرا الداخلية اتقطع بمقص مش اتشد — حد عمل ده بهدوء; الشاتر اتفتح واتقفل تاني — يعني حد معاه مفتاح; الموبايلات اللي اتسرقت كلها آيفون ١٦ برو ماكس — أغلى حاجة في المحل; لقوا كيس أسود كبير ورا المحل فاضي — غالباً استعملوه في النقل; حارس المول قال إنه ما شافش حاجة بس سمع صوت شاتر الساعة ٣ الفجر', 'تامر — المدير — كان آخر واحد في المحل يوم الخميس وقفل الشاتر; تامر عنده صاحب بيشتغل في تجارة موبايلات مستعملة في السيدة زينب; لقوا إن تامر نسخ مفتاح الشاتر عند مفتاحي في الشارع اللي جنب المول; تامر كان بيصور الفاترينة بموبايله قبل السرقة بيوم — قال عشان الجرد; لقوا رسالة من تامر لصاحبه بيقول "عندي بضاعة تحفة هتعجبك"', 'صاحب تامر في السيدة زينب عنده ١٥ آيفون ١٦ برو ماكس وقال إن تامر باعهمله; تامر غيّر عربيته بعد السرقة بأسبوع — اشترى عربية أغلى; مفتاح الشاتر المنسوخ لقوه في بيت تامر في درج المكتب; تامر كان بيكلم صاحبه ٣ مرات يوم الخميس — يوم ما قبل السرقة; الكاميرا بتاعت المول اللي برا صورت تامر داخل المول الساعة ٢:٣٠ بالليل', 'تامر نسخ مفتاح الشاتر وقطع سلك الكاميرا الداخلية لما كان لوحده في المحل يوم الخميس. رجع الساعة ٢:٣٠ بالليل بالمفتاح المنسوخ، حط الموبايلات في كيس أسود وقفل الشاتر ومشي. باع الموبايلات لصاحبه في السيدة زينب واخد الفلوس كاش.', 'أحمد — صاحب المعرض — عنده مشاكل مع شريكه القديم وناس بتقول إنه ممكن يكون عمل السرقة عشان التأمين; يوسف — العامل — كان محتاج فلوس عشان أخوه في المستشفى ومعاه مفتاح الشاتر التالت', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-09'), 'تامر', 1, 'مدير المعرض من سنتين، مسؤول عن البيع والجرد ومعاه مفتاح الشاتر', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-09'), 'أحمد', 2, 'صاحب المعرض، بيجي كل يوم الصبح ومعاه المفتاح الأصلي', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-09'), 'يوسف', 3, 'العامل في المعرض، شاب من الصعيد شغال من سنة وبيقفل المحل أوقات', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-10', 'سرقة', 'مصنع ملابس العبور', 'مصنع ملابس في مدينة العبور، صاحبه الحاج منير فتح يوم السبت لقى مخزن الأقمشة فاضي — أقمشة مستوردة بقيمة مليون ونص اختفت. باب المخزن كان مفتوح بالمفتاح والسيكيوريتي سيستم كان متعطل من يوم الخميس. الحاج منير قال إنه بلّغ عن عطل السيكيوريتي بس محدش صلحه.', 5, 2, 'منى، عصام', 'السيكيوريتي سيستم اتعطل يوم الخميس — حد عبث بيه مش عطل طبيعي; باب المخزن اتفتح بمفتاح ومفيش أي كسر; الأقمشة المسروقة كلها النوع الغالي — حد كان عارف الفرق; لقوا آثار عربية نقل كبيرة عند باب المخزن الخلفي; مفيش أي بصمات غريبة — كل حاجة نضيفة', 'منى — مسؤولة المخزن — كانت آخر واحدة دخلت المخزن يوم الخميس; عصام — فني الصيانة — هو اللي كان المفروض يصلح السيكيوريتي سيستم بس قال "مش فاضي"; منى عندها ورقة فيها كل أنواع الأقمشة وأسعارها ومكانها بالظبط; عصام اتشاف وهو بيتكلم مع سواق نقل يوم الخميس بالليل; لقوا إن منى نسخت مفتاح المخزن — المفتاحي فاكرها', 'عصام هو اللي عطّل السيكيوريتي سيستم — لقوا على اللابتوب بتاعه ملفات فيها كود النظام; منى حوّلت ٢٠٠ ألف جنيه لحساب مش باسمها يوم الأحد; لقوا جزء من الأقمشة المسروقة في مخزن في مدينة السلام — صاحبه قال إن ست وراجل باعوهمله; عصام اشترى عربية لمراته بعد السرقة بأسبوع; رسالة صوتية من منى لعصام بتقول "البضاعة كلها اتباعت الحمد لله"', 'عصام عطّل السيكيوريتي سيستم عمداً يوم الخميس عشان يفضلوا من غير كاميرات. منى استخدمت المفتاح المنسوخ وفتحت المخزن يوم الجمعة بالليل. عصام جاب عربية نقل وحمّلوا الأقمشة الغالية بس. باعوها لتاجر في مدينة السلام وقسموا الفلوس بينهم.', 'الحاج منير — صاحب المصنع — كان عنده مشاكل مع الضرائب وناس شاكة إنه ممكن يكون عملها عشان التأمين; هشام — المحاسب — كان بيلعب قمار وعليه ديون كتير; نورهان — مصممة الأزياء — كانت بتاخد قماش عينات من غير إذن وبتبيعه', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-10'), 'منى', 1, 'مسؤولة المخزن من ٤ سنين، بتعرف كل حاجة عن الأقمشة ومعاها مفتاح المخزن', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-10'), 'عصام', 2, 'فني الصيانة والسيكيوريتي في المصنع، مسؤول عن كل الأنظمة التقنية', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-10'), 'الحاج منير', 3, 'صاحب المصنع، راجل في الستينات ومعروف في مدينة العبور', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-10'), 'هشام', 4, 'محاسب المصنع، شغال من ٣ سنين وبيعرف كل حاجة عن الفلوس', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-10'), 'نورهان', 5, 'مصممة الأزياء في المصنع، بتتعامل مع الأقمشة كل يوم وبتدخل المخزن كتير', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-01', 'خطف', 'اختفاء بنت المدرّس', 'نور، بنت الأستاذ مجدي مدرّس الرياضيات في مدرسة حلوان الإعدادي، مرجعتش من المدرسة. أبوها استناها عند الباب زي كل يوم بس مطلعتش. المدرسة قالت إنها خرجت عادي الساعة ٢ ومحدش شافها بعد كده. الشارع اللي بين المدرسة والبيت مفيهوش كاميرات والناس بتقول كلام مختلف.', 5, 2, 'سميرة، حسام', 'شنطة نور المدرسية لقوها فاضية جنب محل العطارة اللي في نص الشارع; واحد من الجيران قال إنه شاف عربية بيضا واقفة قدام المدرسة فترة طويلة; صاحبتها في الفصل قالت إن نور كانت مستنية حد يعدّيها بعد المدرسة; تليفون نور اتقفل تمام الساعة ٢ وربع; البواب بتاع العمارة قال إنه سمع صريخ بنت صغيرة بس مكانش متأكد', 'كاميرا محل الموبايلات اللي في أول الشارع صوّرت العربية البيضا وكان فيها ست قاعدة في الكرسي اللي جنب السواق; الست اللي في العربية كانت بتكلّم في تليفونها وباين إنها بتنسّق مع حد; نور قالت لصاحبتها الصبح إن ''خالتها'' هتعدّيها النهارده; أبو نور قال مفيش حد من أهله المفروض يعدّيها; لقوا لفافة حلويات في المكان اللي لقوا فيه الشنطة', 'العربية البيضا طلعت مسجّلة باسم مراته بتاعت عم حسام السمكري اللي شغال جنب المدرسة; سميرة الجارة اللي ساكنة تحت الأستاذ مجدي عندها خناقة معاه من شهرين على فلوس; سميرة اتصوّرت وهي بتشتري نفس نوع الحلويات اللي لقوها جنب الشنطة قبلها بيوم; حسام كان قافل محله يوم الحادثة من بدري وقال إنه كان عيان; شهادة صاحبة نور بتقول إن ''الخالة'' دي وصفها شبه سميرة', 'سميرة كانت عايزة تنتقم من الأستاذ مجدي بعد ما رفض يدّيها فلوسها اللي سلّفها إياها. اتفقت مع حسام السمكري إنه يسوق العربية ويستنى قدام المدرسة. سميرة راحت لنور الصبح وقالتلها ''خالتك بعتتني أعدّيكي النهارده'' وادّتها حلويات. نور ركبت العربية وهي مطمّنة. خبّوها في شقة حسام القديمة في التبين وبعتوا لأبوها يطلبوا فلوس.', 'فاطمة — كانت بتحاول تشتري شقة الأستاذ مجدي بسعر رخيص وضغطت عليه كتير; عم صبري — عنده مشاكل مع المدرسة وهدّد الناظر قبل كده; أحمد — شاف نور قبل ما تختفي ومقالش للبوليس في الأول', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-02', 'خطف', 'سواق التوكتوك اللي اختفى', 'عم حسن سواق التوكتوك المشهور في شارع عين شمس اختفى من يومين. التوكتوك بتاعه لقوه واقف في آخر الشارع والموتور شغال. محدش شافه من بعد صلاة العشا. مراته قالت إنه خرج عادي يشتغل ومرجعش. الحتة كلها قلقانة عشان عم حسن راجل طيب ومحبوب.', 3, 1, 'مصطفى', 'التوكتوك بتاعه لقوا فيه شنطة مكانتش بتاعته فيها حبل وشريط لاصق; آخر مشوار عمله كان لواحد اسمه مصطفى عايز يروح منطقة المرج; موبايل عم حسن بعت رسالة لمراته الساعة ١١ بالليل كاتب فيها ''أنا كويس متقلقيش'' بس مراته قالت ده مش أسلوبه', 'مصطفى طلع عنده مخزن قديم في المرج ومحدش بيروحه من زمان; كاميرا كشك السجاير صوّرت التوكتوك وهو داخل شارع المرج الساعة ١٠ بالليل; واحد من سواقين التوكتوك التانيين قال إن مصطفى كان بيسأل عن مواعيد عم حسن من كام يوم; مفيش أي سحب من حساب عم حسن أو أي نشاط على موبايله بعد الرسالة', 'المخزن بتاع مصطفى لقوا فيه أكل جديد وبطانية; جار المخزن قال إنه سمع صوت حد بيخبّط من جوه; مصطفى كان مديون لعم حسن بمبلغ كبير ومش قادر يسدّد; الشريط اللاصق اللي في الشنطة نفس النوع اللي في محل مصطفى', 'مصطفى كان مديون لعم حسن بعشرين ألف جنيه ومش قادر يسدّد. طلب منه مشوار لحد المرج وهناك استدرجه للمخزن القديم وقفله عليه. بعت الرسالة من موبايل عم حسن لمراته عشان محدش يدوّر عليه بسرعة. كان ناوي يخبّيه لحد ما يلاقي طريقة يتخلّص من الدين.', 'كريم — كان عنده خناقة مع عم حسن على أولوية الركاب وهدّده قدام الناس; هدى — بتشتغل في البقالة وعندها مشكلة مع عم حسن عشان باركله التوكتوك قدام المحل', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-03', 'خطف', 'رحلة الفيوم اللي محدش رجع منها', 'مجموعة صحاب نظّموا رحلة للفيوم يوم الجمعة. واحد منهم اسمه شريف اختفى من المعسكر بالليل. صحابه صحيوا الصبح لقوا الخيمة بتاعته فاضية وموبايله على الأرض. المنطقة صحرا ومفيش شبكة والأقرب قرية على بُعد ١٥ كيلو. البوليس وصل بعد ٥ ساعات.', 5, 2, 'عمرو، ياسمين', 'آثار عجل عربية لقوها جنب المعسكر مكانتش موجودة بالليل; شريف كان لابس ساعة غالية ومعاه فلوس كتير; واحد من المجموعة قال إنه سمع صوت موتور عربية الساعة ٣ الفجر; خيمة شريف كانت مفتوحة من برّه مش من جوّه; لقوا علبة مهدّئات فاضية جنب الخيمة', 'عمرو كان عنده عربية تانية مركونة على الطريق الصحراوي على بُعد كيلو من المعسكر; ياسمين اتصوّرت وهي بتحط حاجة في مشروب شريف بالليل قبل ما ينام; آثار العجل طابقت عربية عمرو التانية; شريف كان بيشتكي من صداع شديد بعد ما شرب الشاي اللي ياسمين عملته; واحد من القرية القريبة قال إنه شاف عربية فيها اتنين وراجل نايم ورا', 'ياسمين طلع عندها ديون كبيرة وكانت عارفة إن شريف شايل معاه كاش كتير; عمرو وياسمين اتكلّموا في تليفونات سرّية ٨ مرات في الأسبوع اللي قبل الرحلة; المهدّئات اللي لقوها نفس النوع اللي ياسمين بتاخده بروشتة; عربية عمرو التانية لقوا فيها حبل وبطانية; ياسمين هي اللي اقترحت مكان المعسكر بالظبط', 'ياسمين عرفت إن شريف شايل معاه خمسين ألف كاش للرحلة. اتفقت مع عمرو إنهم يخطفوه ويطلبوا فدية من أهله. ياسمين حطّت مهدّئات في الشاي بتاع شريف. لما نام عمرو راح جاب عربيته التانية وشالوا شريف وهو مش فايق. وصّلوه كوخ مهجور في الصحرا وبعتوا لأهله يطلبوا فلوس.', 'طارق — كان بيغار من شريف عشان بيحب نفس البنت وقالها كلام وحش عنه; مي — كانت مديونة لشريف وعايزة تتخلّص من الدين بأي شكل; سارة — شافت حاجة غريبة بالليل بس خافت تتكلّم عشان هي كانت بتدوّر في شنط الناس', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-04', 'خطف', 'ابن صاحب المطعم', 'آدم ابن أبو سمير صاحب مطعم الكشري الشهير في الدقي اختفى وهو راجع من الدرس الساعة ٧ بالليل. أبو سمير استنّاه في المطعم زي كل يوم بس مجاش. اتصل بالمدرّس قاله آدم مشي من زمان. الشارع كان فاضي بسبب المطر والكاميرات اللي في الشارع مكانتش شغالة بسبب عطل في الكهربا.', 3, 1, 'منى', 'لقوا شنطة آدم المدرسية في زقاق جنب المطعم وفيها ورقة مكتوب فيها ''متقلقش هنرجّعه''; واحدة من الجيران قالت إنها شافت ست محجّبة ماسكة إيد ولد صغير في نفس الوقت; أبو سمير قال إن حد اتصل بيه من رقم مجهول وقفل; آدم كان لابس جاكيت أحمر ومحدش شاف حد لابس أحمر في الشارع بعدها', 'منى اللي بتشتغل كاشيرة في المطعم طلع عندها أخو محبوس وعايزة فلوس كتير للمحامي; الرقم المجهول اللي اتصل بأبو سمير لما اتتبّع طلع من كبينة قريبة من بيت منى; الست المحجّبة اللي الجارة شافتها كانت لابسة نفس لون الإيشارب بتاع منى; منى كانت عارفة مواعيد آدم بالظبط عشان أبوه كان بيبعتها تجيبه أحياناً', 'الورقة اللي لقوها في الشنطة الخط بتاعها طابق خط منى من دفتر الحسابات بتاع المطعم; منى أخدت أجازة اليوم اللي بعد الاختفاء من غير سبب; جارة منى قالت إنها سمعت صوت عيّل بيعيّط في شقة منى بالليل', 'منى كانت محتاجة فلوس ضروري عشان تطلّع أخوها من السجن. عرفت إن أبو سمير عنده فلوس كتير من المطعم. استدرجت آدم وهو راجع من الدرس وقالتله ''أبوك بعتني أجيبك'' وخدته على شقتها. بعتت ورقة لأبو سمير وكانت ناوية تطلب فدية.', 'وليد — كان اتخانق مع أبو سمير قبلها بأسبوع على حسابات وهدّده; فريدة — جارة المطعم اللي بتشتكي من الدوشة وقالت لأبو سمير ''هتندم''', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-05', 'خطف', 'الدكتورة اللي اختفت من العيادة', 'الدكتورة هاجر، دكتورة أسنان مشهورة في المعادي، اختفت من عيادتها يوم الخميس بالليل. الممرضة قالت إن آخر مريض مشي الساعة ٩ والدكتورة قعدت تكمّل شغل لوحدها. لما جوزها راح يجيبها الساعة ١١ لقى العيادة مفتوحة والنور شغال بس هي مش موجودة. شنطتها وموبايلها كانوا لسه على المكتب.', 5, 2, 'باسم، نادية', 'كاميرا العمارة صوّرت راجل لابس كاب دخل العيادة الساعة ١٠ بالليل; لقوا قطنة عليها ريحة كلوروفورم على أرض العيادة; الباب الخلفي للعيادة كان مفتوح مع إن الدكتورة دايماً بتقفله; حد من سكان العمارة قال إنه شاف ست مستنية في عربية سودا تحت; دفتر المواعيد كان فيه اسم مريض مكتوب بالقلم الرصاص ''باسم — ١٠ م'' مكانش في السيستم', 'باسم طلع مش مريض أصلاً ومحدش في العيادة يعرفه; نادية اللي بتشتغل سكرتيرة في عيادة تانية في نفس العمارة طلع عندها مشاكل مالية كبيرة; العربية السودا اللي تحت طلعت مسجّلة باسم نادية; باسم عنده سوابق في قضايا نصب; الكلوروفورم لقوا فاتورة شراه من صيدلية قريبة والكاميرا صوّرت راجل شبه باسم', 'نادية كانت بتتصل بباسم كل يوم في الأسبوع اللي فات; باسم الكاب اللي كان لابسه لقوه في عربية نادية; خط إيد نادية هو اللي كتب اسم باسم في دفتر المواعيد; نادية كانت عارفة إن الدكتورة هاجر بتقعد لوحدها كل خميس; لقوا في موبايل نادية رسايل بتتكلّم عن ''الخطة'' مع رقم باسم', 'نادية كانت عارفة إن جوز الدكتورة هاجر راجل أعمال غني. اتفقت مع باسم إنه يدخل العيادة كمريض وهمي ويخدّر الدكتورة بالكلوروفورم. نادية كانت مستنية في العربية تحت. شالوا الدكتورة من الباب الخلفي وخبّوها في شقة باسم في حلوان. بعتوا لجوزها يطلبوا مليون جنيه فدية.', 'رامي — جوز الدكتورة عنده تأمين كبير عليها وناس كتير شكّت فيه; الممرضة سلمى — كانت متخانقة مع الدكتورة على مرتبها وهدّدت إنها تمشي; عصام — حارس العمارة كان نايم وقت الحادثة ومش عايز يعترف', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-06', 'خطف', 'العروسة اللي ضاعت ليلة فرحها', 'سارة كانت لسه بتتجهّز لفرحها في قاعة في مدينة نصر. دخلت أوضة التجهيز ومرجعتش. صحابها وأهلها دوّروا عليها في القاعة كلها مش موجودة. فستان الفرح لقوه على الكرسي وهي كانت لبست هدوم عادية ومشيت. العريس اتجنّن والفرح اتلغى. بس سارة مبعتتش رسالة لحد ومحدش عارف هي فين.', 3, 1, 'دينا', 'كاميرا القاعة صوّرت سارة وهي خارجة من الباب الخلفي ومعاها واحدة بتمسك إيدها; سارة كانت باينة مش طبيعية في الفيديو وكأنها مش فايقة أوي; لقوا كوباية عصير في أوضة التجهيز فيها بواقي مادة غريبة; دينا صاحبتها هي اللي كانت معاها في الأوضة آخر واحدة; محدش من المعازيم شاف سارة بعد كده', 'دينا طلع عندها سوابق غيرة من سارة وكانت بتحب العريس قبل كده; كاميرات الشارع صوّرت عربية دينا واقفة في الباب الخلفي للقاعة; دينا هي اللي جابت العصير لسارة في أوضة التجهيز; دينا قالت للبوليس إنها مشيت من الأوضة قبل ما سارة تختفي بس الكاميرا بتقول حاجة تانية', 'المادة الغريبة في الكوباية طلعت مهدّئ قوي; دينا اشترت نفس المهدّئ من أسبوع من صيدلية في مصر الجديدة; عربية دينا لقوا فيها شنطة فيها هدوم سارة اللي كانت لابساها; تليفون دينا فيه رسالة لصاحبتها بتقول ''بكره هتتصدموا كلكم''', 'دينا كانت لسه بتحب العريس ومكانتش قادرة تستحمل إنه يتجوّز سارة. حطّت مهدّئ في العصير بتاع سارة وهي بتتجهّز. لما سارة بقت مش فايقة أوي خدتها من الباب الخلفي على عربيتها وقالتلها ''هنروّح عشان تعبتي.'' وصّلتها شقة قديمة في مدينة نصر وقفلت عليها. كانت عايزة الفرح يتلغى بأي شكل.', 'أحمد العريس — ناس قالوا إنه كان متردد في الجواز واتشاف مع بنت تانية; ريم — أخت سارة كانت زعلانة إن سارة بتتجوّز قبلها ومكانتش مبسوطة', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-07', 'خطف', 'الواد اللي اتخطف من النادي', 'يوسف ابن المهندس خالد اتخطف من نادي المعادي الرياضي وهو بيتمرّن. المدرّب قال إنه راح يغيّر هدومه في اللوكر ومرجعش. شنطة الجيم بتاعته لقوها بس هو اختفى. كان فيه ماتش كورة والنادي كان زحمة. كاميرات النادي اتعطّلت من ساعة بسبب صيانة والحراسة مكانتش منتبهة.', 5, 2, 'غادة، شوقي', 'حارس الباب الخلفي للنادي قال إنه شاف واحدة طلعت ومعاها ولد بيعيّط وقالت ''ابني زهق''; شوقي المدرّب الخاص كان آخر واحد اتكلّم مع يوسف قبل ما يروح يغيّر; لقوا في اللوكر ورقة مكتوب فيها ''تعال البوابة الخلفية أبوك مستنيك''; أبو يوسف قال إنه مكانش في النادي أصلاً; كان فيه ريحة كلوروفورم خفيفة في اللوكر', 'غادة العضوة الجديدة في النادي طلع إنها سجّلت من أسبوع بس وبتيجي كل يوم نفس ميعاد يوسف; شوقي المدرّب كان عارف مواعيد يوسف بالظبط وهو اللي قاله يروح يغيّر; غادة كانت واقفة جنب الباب الخلفي في نفس الوقت; الحارس وصف الست اللي طلعت وصفها طابق غادة; شوقي عنده ديون كبيرة من القمار', 'شوقي وغادة طلع بينهم ١٥ مكالمة في آخر أسبوع; غادة اسمها الحقيقي مش غادة والهوية اللي سجّلت بيها في النادي مزوّرة; شوقي هو اللي كتب الورقة اللي في اللوكر — الخط طابق; عربية غادة اتصوّرت وهي خارجة من النادي فيها يوسف في الكرسي الخلفي; لقوا في شنطة غادة إبرة مخدّر', 'شوقي كان مديون بتلاتمية ألف جنيه من القمار. عرف إن أبو يوسف مهندس غني. اتفق مع غادة — واحدة بيعرفها عندها سوابق — إنهم يخطفوا يوسف. شوقي كتب الورقة واستدرج يوسف للوكر. غادة كانت مستنية في الباب الخلفي وخدّرته بإبرة وطلعت بيه كإنه ابنها تعبان. خبّوه في شقة غادة وطلبوا فدية.', 'المهندس خالد — أبو يوسف عنده خناقات مع شريكه وناس بتقول إن الشريك ممكن يكون وراها; عزّت — حارس النادي كان نايم وبيكدب وقال إنه كان صاحي; نورهان — بتشتغل في الكافتيريا وشافت حاجات غريبة بس خافت تتكلّم عشان شغالة من غير تصريح', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-08', 'خطف', 'تاجر الدهب اللي ضاع في السوق', 'الحاج عبدالله تاجر الدهب المعروف في سوق أسيوط اختفى وهو راجع من محله بالليل. المحل لقوه مقفول عادي ومفيش حاجة مسروقة. عربيته لقوها في موقف السوق ومفتاحه لسه فيها. مراته قالت إنه اتصل بيها الساعة ٩ وقالها ''جاي في السكة'' بس مجاش. أسيوط كلها بتدوّر عليه.', 5, 2, 'رضا، إيمان', 'واحد من التجار اللي جنبه قال إنه شاف عربية ميكروباص غريبة واقفة قدام المحل; الحاج عبدالله كان معاه شنطة فيها دهب قيمتها كبيرة رايح يوصّلها لزبون; لقوا تليفون الحاج عبدالله في سلّة زبالة قريبة من الموقف; رضا ابن أخوه كان في السوق في نفس الوقت مع إنه مبيجيش بالليل; واحدة محجّبة اتشافت وهي بتتكلّم مع الحاج عبدالله قبل ما يقفل', 'رضا طلع عليه ديون كتير ومحتاج فلوس ضروري; إيمان اللي بتشتغل محاسبة عند الحاج عبدالله هي الست اللي اتشافت بتتكلّم معاه; الميكروباص طلع بتاع صاحب رضا; إيمان هي اللي عارفة إنه هيشيل دهب معاه في اليوم ده; رضا كان بيسأل عن الكاميرات في السوق وإمتى بتتقفل', 'إيمان بعتت رسالة لرضا الساعة ٨ ونص قالتله ''خلاص ماشي بالدهب دلوقتي''; الميكروباص لقوه في قرية برّه أسيوط وفيه آثار حبل; رضا غيّر موبايله اليوم اللي بعد الاختفاء; إيمان عندها حساب بنك فيه تحويلات غريبة من رضا; واحد في القرية قال إنه شاف راجل وست دخّلوا راجل كبير في بيت مهجور', 'رضا كان عايز فلوس عشان يسدّد ديونه وعرف من إيمان إن عمّه هيشيل دهب كتير. إيمان وافقت تساعده عشان هي كمان محتاجة فلوس. إيمان أخّرت الحاج عبدالله عند المحل بحجة إنها عايزة توقيعه على ورق. رضا جه بالميكروباص وصاحبه. لما الحاج عبدالله طلع خطفوه وخدوا الدهب. خبّوه في بيت مهجور في قرية برّه أسيوط.', 'سعيد — تاجر منافس وكان متخانق مع الحاج عبدالله على زبون كبير; أم رضا — كانت زعلانة من أخوها الحاج عبدالله على ميراث ومكلّمتوش من سنة; جابر — حارس السوق بالليل كان سايب مكانه ومش عايز يقول كان فين', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-09', 'خطف', 'المحامية اللي اختفت من محطة رمسيس', 'الأستاذة نجلاء محامية مشهورة كانت راكبة قطر الصعيد من محطة رمسيس. نزلت من القطر في محطة بني سويف بس مطلعتش من المحطة. كاميرا المحطة صوّرتها وهي نازلة من القطر ومشيت ناحية الباب ومبانتش تاني. شنطة السفر بتاعتها لقوها على الرصيف. زمايلها في المكتب بلّغوا لما مردّتش على تليفونها يومين.', 3, 1, 'حاتم', 'حاتم سواق الأجرة اللي واقف برّه المحطة هو آخر واحد اتشاف بيتكلّم معاها; واحد من الركاب قال إن ست مشيت ناحية الأجرة بتاعت حاتم وركبت; الأستاذة نجلاء كانت شغالة على قضية كبيرة ضد ناس خطيرة; موبايلها اتقفل وهي لسه في المحطة; لقوا إيشاربها على الأرض قريب من العربية', 'حاتم طلع مش سواق أجرة حقيقي والرخصة بتاعته منتهية; العربية بتاعت حاتم مفيهاش GPS شغال ومحدش يعرف راحت فين; حاتم اتشاف في محطة رمسيس ٣ مرات في الأسبوع اللي فات مع إنه مش من القاهرة; الأستاذة نجلاء كانت مفروض تقابل موكّلها في بني سويف بس مرحتش; حاتم غيّر العربية بتاعته اليوم اللي بعدها', 'حاتم طلع قريب واحد من المتهمين في القضية اللي نجلاء شغالة عليها; عربية حاتم القديمة لقوها متحرقة في منطقة زراعية برّه بني سويف; حاتم عنده سوابق في قضايا تهديد; شاهد في القرية القريبة قال إنه شاف راجل بينقل ست لعربية تانية الليلة دي', 'حاتم كان قريب المتهم الرئيسي في قضية نجلاء. المتهم طلب منه يتخلّص من المحامية قبل الجلسة الجاية. حاتم استنى نجلاء في محطة بني سويف متنكّر كسواق أجرة. لما ركبت خدّرها وراح بيها على بيت في قرية مهجورة. حرق العربية عشان يمسح الأدلة. كان ناوي يخبّيها لحد ما القضية تخلص.', 'وائل — زميل نجلاء في المكتب كان عايز يتولّى القضية بدالها وكان بيضغط عليها تسيبها; سهام — سكرتيرة المكتب كانت بتسرّب معلومات القضايا ومش عايزة حد يعرف', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-10', 'خطف', 'صاحب الصيدلية اللي طار', 'الدكتور مازن صاحب أكبر صيدلية على كورنيش اسكندرية اختفى فجأة. المحل كان مفتوح والموظفين جوّه بس هو راح يجيب حاجة من العربية ومرجعش. عربيته لقوها في الموقف مفتوحة ومفتاحه على الأرض. كان فيه حفلة على الكورنيش والناس كتير ومحدش انتبه. زوجته بلّغت البوليس بعد ٣ ساعات.', 5, 2, 'زياد، لمياء', 'لقوا تليفون مازن في صندوق زبالة على الكورنيش ومفيه رسالة غريبة بتقول ''خلاص وصّلناه''; زياد الصيدلي اللي شغال معاه كان آخر واحد شافه قبل ما يروح العربية; لمياء اللي بتشتغل ممرضة في صيدلية منافسة كانت واقفة على الكورنيش في نفس الوقت; واحد بيبيع ذرة على الكورنيش قال إنه شاف اتنين ساندوا راجل في يخت صغير; مازن كان بيتكلّم مع حد في التليفون وباين متوتّر قبل ما يطلع', 'زياد طلع عنده مشروع صيدلية خاصة بيه ومحتاج رأس مال كبير; لمياء عندها علاقة شراكة سرّية مع زياد عشان يفتحوا صيدلية مع بعض; اليخت اللي بيّاع الذرة شافه طلع مأجّر باسم مزيّف بس رقم التليفون اللي حجز بيه بتاع لمياء; زياد هو اللي قال لمازن ''روح جيب الحاجة من العربية أنا هكمّل هنا''; لمياء اتشافت وهي بتتكلّم مع اتنين شباب قبلها بنص ساعة على الكورنيش', 'الشباب اللي كانوا مع لمياء طلعوا بحّارة وهم اللي سواقين اليخت; زياد بعت رسالة للمياء الساعة ٩ بالليل ''خلاص طلع''; لمياء حوّلت فلوس للبحّارة قبلها بيوم; زياد كان مستفيد من غياب مازن عشان يتحكّم في الصيدلية; اليخت رسى في مارينا قريبة وحد شاف راجل مربوط الإيدين بيتنقل لعربية', 'زياد كان عايز يبقى صاحب صيدلية بدل ما يفضل موظف. اتفق مع لمياء إنهم يخطفوا مازن ويطلبوا فلوس من أهله وفي نفس الوقت يسيطروا على الصيدلية. زياد خلّى مازن يطلع من المحل ولمياء كانت مجهّزة اليخت مع البحّارة. ساندوه ودخّلوه اليخت وفي المارينا نقلوه لمكان مخبّي في برج العرب.', 'عادل — شريك مازن القديم اللي اتخانق معاه واتفصل من الشراكة وبيهدّده بقضايا; هالة — مراته اللي عندها تأمين كبير عليه وناس شكّت فيها; كريم — زبون دايم عنده مشاكل مع الصيدلية على أدوية وكان بيعمل مشاكل كتير', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-01'), 'سميرة', 1, 'الجارة اللي ساكنة تحت الأستاذ مجدي. ست في الأربعينات بتشتغل خياطة من البيت. بتعرف كل حاجة عن الناس في العمارة وعندها مفتاح بتاع باب العمارة.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-01'), 'حسام', 2, 'السمكري اللي محله جنب المدرسة. راجل في الخمسينات ساكت وبيشتغل لوحده. الناس بتقول إنه طيب بس غامض شوية.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-01'), 'فاطمة', 3, 'سمسارة عقارات في المنطقة. بتلف على العمارات وبتعرض تشتري شقق. ست شاطرة في الكلام وبتعرف تقنع أي حد.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-01'), 'عم صبري', 4, 'البواب بتاع العمارة اللي قدام المدرسة. راجل كبير عنده مشاكل مع إدارة المدرسة عشان ولاده اتطردوا.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-01'), 'أحمد', 5, 'طالب ثانوي ساكن في نفس الشارع. ولد هادي بيروح المدرسة وييجي بس الناس بتقول إنه بيحب يتفرّج على الناس من البلكونة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-02'), 'مصطفى', 1, 'راجل في التلاتينات بيشتغل في محل موبايلات في عين شمس. معروف إنه بيحب الفلوس وعنده شغل جانبي محدش فاهمه.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-02'), 'كريم', 2, 'سواق توكتوك تاني في نفس المنطقة. شاب في العشرينات عصبي شوية وعنده منافسة مع عم حسن على الزباين.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-02'), 'هدى', 3, 'صاحبة البقالة اللي في أول الشارع. ست في الأربعينات حازمة وبتتخانق مع أي حد يقرب من قدام محلها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-03'), 'عمرو', 1, 'صاحب شريف من أيام الجامعة. بيشتغل محاسب في شركة. بيحب الرحلات ومعروف إنه بيخطّط كل حاجة بالتفصيل.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-03'), 'ياسمين', 2, 'صاحبة شريف من الشغل. بتشتغل في شركة أدوية. بنت اجتماعية وهي اللي نظّمت الرحلة ورتّبت كل حاجة.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-03'), 'طارق', 3, 'صاحب شريف من المدرسة. بيشتغل مهندس. ولد ساكت بس لما بيتكلّم بيقول كلام كبير. بيغار من شريف شوية.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-03'), 'مي', 4, 'بنت جديدة في المجموعة عرّفها طارق عليهم. بتشتغل في بنك وبتحب المغامرات. محدش يعرف عنها كتير.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-03'), 'سارة', 5, 'صاحبة شريف القديمة. بتشتغل صحفية. بنت فضولية وبتحب تدوّر في كل حاجة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-04'), 'منى', 1, 'الكاشيرة في مطعم أبو سمير من سنتين. ست في التلاتينات هادية وبتشتغل كويس. الناس بتحبها في المطعم.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-04'), 'وليد', 2, 'المحاسب القديم بتاع المطعم. اتخانق مع أبو سمير على حسابات ومشي من الشغل. لسه بيجي الحتة وبيتكلّم مع الناس.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-04'), 'فريدة', 3, 'صاحبة محل الملابس اللي جنب المطعم. ست في الخمسينات عصبية وبتشتكي من دوشة المطعم على طول.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-05'), 'باسم', 1, 'راجل في الأربعينات محدش يعرف عنه حاجة. ظهر فجأة في المنطقة من شهر. بيقول إنه راجع من برّه بس مفيش حد يعرف بلده.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-05'), 'نادية', 2, 'سكرتيرة في عيادة تانية في نفس العمارة. بنت في التلاتينات شاطرة ودمها خفيف. بتعرف كل الدكاترة في العمارة.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-05'), 'رامي', 3, 'جوز الدكتورة هاجر. راجل أعمال ناجح عنده شركة مقاولات. بيحب مراته بس شغله بياخده من البيت كتير.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-05'), 'سلمى', 4, 'الممرضة بتاعت الدكتورة هاجر من ٥ سنين. بنت مجتهدة بس زهقت من المرتب القليل وعايزة تمشي.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-05'), 'عصام', 5, 'حارس العمارة بالليل. راجل كبير نعسان على طول. بيقعد على الكرسي قدام الباب وبينام أوقات كتير.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-06'), 'دينا', 1, 'أقرب صاحبة لسارة من أيام الجامعة. بنت جميلة وشاطرة بس الناس بتقول إنها بتغير من سارة أحياناً.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-06'), 'أحمد', 2, 'العريس. مهندس في شركة كبيرة. ولد محترم بس كان باين عليه التوتر في الفترة اللي قبل الفرح.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-06'), 'ريم', 3, 'أخت سارة الصغيرة. بنت في العشرينات لسه في الجامعة. كانت مش مبسوطة أوي إن أختها بتتجوّز قبلها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-07'), 'غادة', 1, 'عضوة جديدة في النادي. ست في التلاتينات أنيقة ومحدش يعرف عنها حاجة. بتيجي تتمرّن كل يوم.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-07'), 'شوقي', 2, 'مدرّب اللياقة الخاص في النادي. راجل في الأربعينات قوي ومعروف إنه بيحب يصرف كتير ودايماً محتاج فلوس.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-07'), 'المهندس خالد', 3, 'أبو يوسف. راجل أعمال ناجح عنده شركة مقاولات كبيرة. بيحب ابنه جداً بس مشغول في الشغل على طول.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-07'), 'عزّت', 4, 'حارس النادي من ١٠ سنين. راجل كبير ساكت وبيعمل شغله. بس الناس بتقول إنه بينام في الخدمة أحياناً.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-07'), 'نورهان', 5, 'بتشتغل في كافتيريا النادي. بنت في العشرينات هادية ومش بتتكلّم كتير. بتشوف كل حاجة بتحصل في النادي.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-08'), 'رضا', 1, 'ابن أخو الحاج عبدالله. شاب في التلاتينات بيشتغل في محل عطارة صغير. محتاج فلوس على طول وعمّه مش بيساعده.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-08'), 'إيمان', 2, 'المحاسبة بتاعت الحاج عبدالله من ٣ سنين. ست في التلاتينات شاطرة في الأرقام وعارفة كل تفاصيل الشغل.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-08'), 'سعيد', 3, 'تاجر دهب تاني في نفس السوق. راجل في الخمسينات عنده منافسة شرسة مع الحاج عبدالله من زمان.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-08'), 'أم رضا', 4, 'أخت الحاج عبدالله. ست كبيرة زعلانة من أخوها على موضوع ميراث أبوهم. مبتكلّموش من سنة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-08'), 'جابر', 5, 'حارس السوق بالليل. راجل في الأربعينات بيشتغل نوبتجي. معروف إنه بيسيب مكانه أحياناً يروح القهوة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-09'), 'حاتم', 1, 'سواق أجرة واقف برّه محطة بني سويف. راجل في الأربعينات شكله عادي ومحدش بياخد باله منه.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-09'), 'وائل', 2, 'زميل نجلاء في مكتب المحاماة. محامي شاطر بس طموح أوي وعايز يبقى الشريك الأول في المكتب.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-09'), 'سهام', 3, 'سكرتيرة مكتب المحاماة. ست في التلاتينات بتعرف كل أسرار القضايا وعندها وصول لكل الملفات.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-10'), 'زياد', 1, 'الصيدلي اللي شغال مع الدكتور مازن من ٤ سنين. شاب في التلاتينات طموح وعايز يفتح صيدلية لوحده.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-10'), 'لمياء', 2, 'ممرضة في صيدلية منافسة على الكورنيش. بنت في التلاتينات ذكية وبتعرف ناس كتير في المنطقة.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-10'), 'عادل', 3, 'شريك الدكتور مازن القديم. راجل في الخمسينات اتفصل من الشراكة وزعلان جداً. بيهدّد بقضايا.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-10'), 'هالة', 4, 'مرات الدكتور مازن. ست أنيقة في الأربعينات. الناس بتقول إن علاقتها بجوزها مش أحسن حاجة الفترة دي.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-10'), 'كريم', 5, 'زبون دايم في الصيدلية. راجل في الأربعينات عصبي وبيعمل مشاكل كتير على الأدوية والأسعار.', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-01', 'ابتزاز', 'رسالة لمدير المدرسة', 'في مدرسة خاصة في أكتوبر، مدير المدرسة أبو سمير لقى رسالة على الواتساب من نمرة مجهولة فيها صور قديمة ليه من أيام ما كان بيشتغل في مدرسة تانية، والراسل بيقوله ادفع مية ألف جنيه ولا الصور دي هتتنشر لأولياء الأمور. أبو سمير اتصدم عشان الصور دي مكانش يعرف إنها موجودة أصلاً.', 5, 2, 'كريم، إسلام', 'حد من اللي شغالين في المدرسة عنده وصول للأرشيف القديم بتاع الموظفين؛ الرسالة وصلت بالظبط قبل اجتماع مجلس الأمناء بيومين؛ أكتر من واحد في المدرسة عنده مشكلة مع أبو سمير من زمان؛ الصور دي مش منتشرة ومحدش كان المفروض يوصلها غير حد من جوه.', 'واحد من الموجودين كان بيدور في كمبيوتر الإدارة من ورا أبو سمير؛ حد تاني اتواصل مع مدرسة أبو سمير القديمة الأسبوع اللي فات؛ فيه خناقة قديمة بين أبو سمير وواحد من المدرسين على موضوع ترقية؛ الرسالة كانت مكتوبة بأسلوب حد فاهم في التكنولوجيا.', 'الرسالة اتبعتت من شبكة الواي فاي بتاعت المدرسة نفسها؛ واحد من الناس اللي هنا كان عنده نسخة من الصور على فلاشة قبل ما الرسالة توصل؛ الأسلوب اللي الرسالة مكتوبة بيه فيه كلمات معينة بيستخدمها حد بعينه في المدرسة؛ أبو سمير كان ناوي يفصل حد قبل ما الرسالة توصل.', 'كريم هو المدرس اللي أبو سمير كان هيفصله، راح اتواصل مع المدرسة القديمة وجاب الصور، وإسلام اللي مسؤول عن الكمبيوترات ساعده يبعت الرسالة من نمرة وهمية ومن شبكة المدرسة عشان محدش يعرف تتبعها.', 'هاجر كانت بتدور في ملفات الإدارة عشان تلاقي عقدها القديم اللي ضاع؛ مصطفى كان بيحضر لشكوى رسمية ضد أبو سمير بسبب مكافآت مظلوم فيها؛ منى اتصلت بالمدرسة القديمة عشان تسأل على طريقة تدريس مش أكتر.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-01'), 'هاجر', 1, 'المشرفة الإدارية اللي شغالة في المدرسة من عشر سنين وبتتعامل مع كل الملفات والأوراق', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-01'), 'كريم', 2, 'المدرس اللي اتنقل من مدرسة تانية السنة اللي فاتت وعنده مشاكل مع الإدارة على موضوع التقييم', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-01'), 'إسلام', 3, 'مسؤول الكمبيوترات والشبكات في المدرسة وهو اللي بيظبط كل الأجهزة والسيستم', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-01'), 'مصطفى', 4, 'مدرس رياضيات قديم في المدرسة وليه خلافات مع أبو سمير على المكافآت والحوافز', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-01'), 'منى', 5, 'مدرسة إنجليزي جديدة لسه جاية المدرسة دي من أول الترم وبتحاول تفهم النظام', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-02', 'ابتزاز', 'تسجيل في الكافيه', 'في كافيه مشهور في المعادي، صاحب الكافيه عمرو لقى رسالة فيها تسجيل صوتي ليه وهو بيتكلم مع شريكه عن تحويلات فلوس مش قانونية. اللي باعتها بيطلب خمسين ألف جنيه كل شهر ولا التسجيل ده هيوصل للضرايب. عمرو مش فاهم مين اللي سجله عشان الكلام ده كان في أوضة مقفولة في الكافيه.', 3, 1, 'دينا', 'التسجيل ده من جوه أوضة المكتب الخاص بتاع عمرو في الكافيه؛ الكلام اللي في التسجيل كان من أسبوعين بس؛ حد لازم كان قريب أو حاطط حاجة في الأوضة عشان يسجل.', 'دينا كانت أول واحدة وصلت الكافيه الصبح ده وكان عندها مفتاح المكتب؛ فيه موبايل قديم اتلقى تحت الكنبة في المكتب ممكن يكون اتحط عشان يسجل؛ طارق كان بيشتكي إن مرتبه قليل وعايز يمشي من الكافيه.', 'الموبايل اللي اتلقى كان مسجل عليه ابليكيشن تسجيل وشغال من أسبوعين؛ حد اشترى الموبايل ده كاش من محل قريب من المعادي؛ دينا كانت عارفة كل مواعيد اجتماعات عمرو مع شريكه عشان هي اللي بتنظم الجدول بتاعه.', 'دينا هي اللي حطت الموبايل في المكتب عشان تسجل عمرو، والسبب إن عمرو كان بيأخرها في حصتها من الأرباح اللي كان وعدها بيها لما فتحوا الكافيه، فقررت تبتزه بالتسجيل عشان تاخد فلوسها وزيادة.', 'طارق كان بياخد أكل من المطبخ من غير ما يسجله وخايف لو عمرو عرف هيفصله؛ سارة كانت بتستخدم واي فاي الكافيه عشان تشتغل شغل تاني من ورا عمرو.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'دينا', 1, 'مديرة الكافيه اللي بتنظم كل حاجة من المواعيد للحسابات وشغالة مع عمرو من أول ما فتح', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'طارق', 2, 'الشيف الأساسي في الكافيه واللي مسؤول عن المطبخ وبيشتكي دايماً من المرتب', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'سارة', 3, 'البنت اللي شغالة باريستا في الكافيه بقالها ست شهور وبتقعد لوحدها كتير بعد الشيفت', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-03', 'ابتزاز', 'إيميلات المدير المالي', 'في شركة كبيرة في التجمع الخامس، المدير المالي أحمد بدأ يوصله إيميلات فيها سكرين شوتات من إيميلاته الخاصة، واللي باعتها بيهدده إنه هينشر المراسلات دي اللي فيها اتفاقات جانبية مع موردين لو مدفعش تلتمية ألف جنيه. أحمد اتخض عشان الإيميلات دي مكانتش غير على جهازه هو بس.', 5, 2, 'حسام، هدى', 'حد وصل لجهاز أحمد أو للإيميل بتاعه من غير ما يحس؛ السكرين شوتات واضح إنها من جهاز أحمد نفسه مش من جهاز تاني؛ أكتر من واحد في الشركة عنده سبب يضغط على أحمد؛ الإيميلات اللي اتصورت كلها عن صفقة واحدة بعينها.', 'حسام كان قاعد لوحده في مكتب أحمد يوم الإجازة عشان "يخلّص شغل ضروري"؛ هدى طلبت من الـ IT يفتحوا لها صلاحيات على السيرفر الأسبوع اللي فات؛ فيه حد في الشركة عنده باسورد أحمد القديم قبل ما يتغير؛ الإيميلات المبتز استخدمها كلها من آخر شهرين بس.', 'لوج السيرفر بيقول إن حد دخل على إيميل أحمد من جهاز في الشركة مش جهازه؛ الجهاز ده كان في مكتب مشترك بين حسام وهدى؛ واحد منهم نقل الملفات على USB بعد ما صورها؛ أحمد كان ناوي يبلغ عن مخالفات في قسم المشتريات واللي كان هيتأثر أكتر من حد.', 'حسام هو اللي دخل على الإيميل من جهاز المكتب المشترك وصور السكرين شوتات، وهدى اللي شغالة في المشتريات ساعدته عشان هي كمان كانت متورطة في الصفقات الجانبية مع الموردين واللي أحمد كان هيكشفها.', 'شريف كان بيدور في ملفات أحمد عشان يلاقي تقرير كان محتاجه لعرض تقديمي؛ مي طلبت صلاحيات سيرفر عشان مشروع حقيقي بس التوقيت كان وحش؛ عمرو كان عارف باسورد أحمد القديم عشان أحمد نفسه اداهوله مرة يفتحله ملف.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-03'), 'شريف', 1, 'مدير التسويق اللي في الشركة من خمس سنين وبينه وبين أحمد منافسة على منصب نائب المدير العام', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-03'), 'حسام', 2, 'محاسب أول في القسم المالي وبيشتغل تحت إيد أحمد وعنده طموح ياخد مكانه', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-03'), 'هدى', 3, 'مسؤولة المشتريات اللي بتتعامل مع كل الموردين وعندها علاقات كتير بره الشركة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-03'), 'مي', 4, 'مهندسة الـ IT اللي مسؤولة عن السيرفرات والصلاحيات وبتحل كل المشاكل التقنية', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-03'), 'عمرو', 5, 'المساعد الشخصي لأحمد واللي بيعرف كل مواعيده وبيدخل مكتبه كل يوم', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-04', 'ابتزاز', 'صور من العيادة', 'في عيادة تجميل مشهورة في الزمالك، الدكتورة فاطمة بدأت توصلها صور مريضات قبل وبعد العمليات من ملفاتها السرية، واللي باعتها بيقولها لو مدفعتيش ربع مليون الصور دي هتتنشر على السوشيال ميديا. فاطمة اتجننت عشان الصور دي مينفعش حد يوصلها غير من جوه العيادة.', 5, 2, 'نور، أبو سمير', 'الصور اتاخدت من السيستم بتاع العيادة مش من موبايل حد؛ الملفات دي محدش بيوصلها غير اللي عنده صلاحيات على الكمبيوتر؛ الابتزاز بدأ بعد ما فاطمة رفضت تجدد عقد واحد من الموظفين؛ الصور كلها لمريضات VIP ودي معناها إن اللي سرقها عارف مين المهم.', 'نور كانت بتقعد بعد المواعيد وحدها في العيادة "تخلّص ورق"؛ أبو سمير اللي بيعمل صيانة بيفضل في العيادة لوحده بالليل؛ حد استخدم كمبيوتر الريسيبشن في وقت مفيش حد؛ فيه USB اتشالت من درج الدكتورة ومكانش حد واخد باله.', 'لوج الكمبيوتر بيقول إن حد فتح ملفات المريضات الساعة ١١ بالليل؛ كاميرا المدخل بتبين إن اتنين كانوا في العيادة الوقت ده؛ نور كانت عارفة باسورد فاطمة عشان فاطمة كانت بتقولهالها تفتح لها حاجات؛ أبو سمير عنده مفتاح كل الأوض في العيادة.', 'نور هي اللي دخلت على الكمبيوتر بالليل ونزّلت ملفات المريضات على USB، وأبو سمير هو اللي فتحلها العيادة وساعدها تدخل من غير ما الكاميرات تسجل كويس عشان هو اللي بيتحكم في نظام المراقبة. الاتنين كانوا عايزين فلوس عشان نور هتتفصل وأبو سمير مرتبه قليل.', 'ياسمين كانت بتصور سكرين شوت لجدول المريضات عشان تنظم شغلها على موبايلها الشخصي؛ محمد كان بيستخدم كمبيوتر الريسيبشن يلعب عليه بعد الشغل؛ هند كانت بتنقل ملفات على إيميلها عشان تشتغل عليها من البيت بتكليف من فاطمة بس من غير إذن رسمي.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-04'), 'ياسمين', 1, 'ممرضة في العيادة من تلت سنين وبتتعامل مع كل المريضات وعندها وصول لملفاتهم', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-04'), 'نور', 2, 'السكرتيرة اللي فاطمة كانت ناوية متجددلهاش العقد وعارفة كل باسوردات العيادة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-04'), 'محمد', 3, 'دكتور التخدير اللي بيشتغل نص وقت في العيادة وبييجي بالليل ساعات يخلّص ورق', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-04'), 'أبو سمير', 4, 'عامل الصيانة والنظافة اللي عنده مفاتيح كل حاجة في العيادة وبيبات فيها أحياناً', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-04'), 'هند', 5, 'مساعدة الدكتورة فاطمة الشخصية وبتتعامل مع الملفات الحساسة وبتشيلها على إيميلها', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-05', 'ابتزاز', 'فيديو المكتب', 'في مكتب محاماة في الدقي، المحامي الكبير عم حسن لقى لينك لفيديو على يوتيوب مخفي فيه تسجيل ليه وهو بياخد رشوة من عميل. اللي باعتله اللينك بيقوله لو مدفعش ميتين ألف الفيديو هيتحط عالعام. عم حسن عارف إن الموضوع ده حصل في مكتبه، بس مكانش فيه كاميرات!', 3, 1, 'فاطمة', 'التسجيل من زاوية غريبة في المكتب كأن حد حاطط كاميرا صغيرة؛ الحادثة اللي في الفيديو حصلت من شهر واللي صورها كان عارف الميعاد بالظبط؛ محدش كان في المكتب غير تلت أشخاص يوم ما الحادثة حصلت.', 'فاطمة كانت في المكتب يوم التسجيل عشان كانت بتجهز ملفات؛ حد اشترى كاميرا صغيرة من أمازون واتشحنت على عنوان قريب من الدقي؛ أحمد كان عنده خناقة مع عم حسن على مكافأة نهاية السنة.', 'الكاميرا اتلقت مخبية ورا الكتب في رف المكتبة اللي جنب مكتب عم حسن؛ بصمات على الكاميرا بتاعت واحد من اللي في المكتب؛ فاطمة هي الوحيدة اللي كانت بترتب الرف ده كل أسبوع؛ اللينك اتبعت من إيميل متعمل على جهاز كان متوصل بشبكة المكتب.', 'فاطمة هي اللي حطت الكاميرا في المكتبة عشان عم حسن كان بيتحرش بيها وهي كانت عايزة دليل، بس لما لقت تسجيل الرشوة قررت تبتزه بيه بدل ما تبلغ عشان تاخد فلوس وتمشي.', 'أحمد كان بيفكر يسيب المكتب ويفتح مكتب لوحده وبيسرق بيانات عملاء عم حسن عشان ياخدهم معاه؛ مصطفى كان عارف موضوع الرشوة عشان هو اللي جاب العميل بس مكانش عايز يتكلم عشان هياخد نسبة.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-05'), 'فاطمة', 1, 'السكرتيرة اللي شغالة مع عم حسن من خمس سنين وبترتب كل حاجة في المكتب', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-05'), 'أحمد', 2, 'المحامي الشاب اللي بيشتغل مع عم حسن وطامع يستقل ويفتح مكتبه الخاص', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-05'), 'مصطفى', 3, 'المحامي التاني في المكتب واللي بيجيب عملاء كتير وعارف كل أسرار القضايا', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-06', 'ابتزاز', 'ليلة مارينا', 'في حفلة خاصة في شاليه في مارينا، رجل أعمال اسمه شريف لقى صور ليه مع ست مش مراته على موبايله في رسالة من نمرة مش معروفة. الرسالة بتقول: "نص مليون ولا الصور دي هتوصل لمراتك ولشريكك في الشغل." الصور اتاخدت في الحفلة نفسها من كام ساعة بس.', 5, 2, 'عمرو، ياسمين', 'الصور اتاخدت من زاوية قريبة في الحفلة يعني اللي صورها كان موجود؛ الحفلة كانت صغيرة ومفيهاش غير ناس معدودة؛ حد في الحفلة كان ماسك موبايله كتير وبيصور؛ شريف عنده أعداء في الشغل ممكن يستغلوا حاجة زي دي.', 'عمرو كان قاعد في نفس الترابيزة وماسك موبايله طول الوقت؛ ياسمين كانت بتلف في الشاليه كتير وراحت عند حمام السباحة اللي الصور اتاخدت جنبه؛ فيه حد في الحفلة عنده تطبيق تعديل صور متقدم على موبايله؛ شريف كان وعد حد بشراكة ونكث في وعده.', 'الصور الأصلية اتلاقت على موبايل واحد من الموجودين في الألبوم المحذوف؛ الرسالة اتبعتت من تطبيق أرقام وهمية واللي نزّله كان متوصل بالواي فاي بتاع الشاليه؛ عمرو وياسمين كانوا بيتكلموا لوحدهم في البلكونة قبل ما الرسالة توصل بنص ساعة؛ شريف كان ناوي يشيل عمرو من مشروع كبير.', 'عمرو هو اللي صور الصور عشان شريف كان هيطلعه من مشروع هيكسبهم ملايين، وياسمين اللي شغالة PR ساعدته يبعت الرسالة من تطبيق أرقام وهمية وعدّلت الصور عشان تبان أوضح. الاتنين كانوا متفقين ياخدوا الفلوس ويقسموها.', 'مي كانت بتصور كل حاجة في الحفلة عشان تحطها على إنستجرام ومسحت صور كتير بعد كده؛ حسن كان عنده خناقة مع شريف على فلوس قديمة ومكانش مبسوط منه؛ سلمى كانت بتكلم مرات شريف على الموبايل قبل الحفلة عشان تنسق مفاجأة عيد ميلاد مش أكتر.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-06'), 'مي', 1, 'صاحبة شريف من أيام الجامعة وبتحب تصور كل حاجة وتحطها على السوشيال ميديا', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-06'), 'عمرو', 2, 'شريك شريف في مشروع عقاري واللي شريف كان ناوي يشيله من المشروع', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-06'), 'حسن', 3, 'صاحب شريف القديم واللي بينهم خلاف على فلوس من سفرية قديمة', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-06'), 'ياسمين', 4, 'البنت اللي شغالة PR وبتنظم حفلات شريف وعندها كل أرقامه وبياناته', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-06'), 'سلمى', 5, 'صاحبة مرات شريف وكانت موجودة في الحفلة وبتتكلم مع كل الناس', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-07', 'ابتزاز', 'ملفات المصلحة', 'في مصلحة حكومية في العباسية، الموظف الكبير أبو محمد بدأ يوصله ظروف مقفولة فيها صور لمستندات بتثبت إنه بيوافق على معاملات مخالفة مقابل رشاوي. كل ظرف فيه ورقة مكتوب عليها مبلغ أكبر من اللي قبله. أبو محمد مش فاهم الصور دي اتاخدت إزاي عشان المستندات دي في خزنته المقفولة.', 5, 2, 'قاسم، هاجر', 'الصور اتاخدت للمستندات وهي على مكتب أبو محمد مش في الخزنة يعني اللي صورها كان موجود وقت ما أبو محمد كان بيشتغل عليها؛ الظروف بتوصل على مكتبه الصبح يعني حد بيدخل قبله؛ أكتر من واحد في المصلحة عنده مشكلة مع أبو محمد.', 'قاسم بتاع الأمن هو اللي بيفتح المصلحة الصبح وعنده مفاتيح كل المكاتب؛ هاجر شغالة في الأرشيف وبتدخل مكتب أبو محمد كل يوم تجيبله ملفات؛ فيه حد صور المستندات بموبايله وطبعها في مكتبة قريبة من العباسية؛ أبو محمد كان ناوي يعمل تحقيق في قسم الأرشيف.', 'كاميرا المدخل بتبين إن قاسم كان بيدخل المصلحة الساعة ٦ الصبح قبل أي حد بساعة؛ مكتبة جنب المصلحة فيها طلب طباعة صور بنفس الحجم والنوع؛ هاجر كانت بتقعد لوحدها في مكتب أبو محمد وقت الضهر لما هو بيكون في الاجتماعات؛ الاتنين كانوا بيتكلموا كتير على الموبايل الفترة الأخيرة.', 'قاسم هو اللي كان بيحط الظروف على المكتب الصبح بدري قبل ما حد ييجي عشان عنده مفاتيح كل حاجة، وهاجر هي اللي صورت المستندات بموبايلها لما كانت بتدخل مكتبه وقت ما هو في الاجتماعات. الاتنين عايزين فلوس عشان قاسم ابنه محتاج عملية وهاجر عليها ديون.', 'نزار كان بيدخل مكتب أبو محمد يوقّعله ورق ضروري وشاف المستندات دي على المكتب بس مقالش لحد؛ سعاد كانت بتطبع حاجات شخصية في المكتبة اللي جنب المصلحة ومش عايزة حد يعرف؛ فراس صاحب المعاملة كان بيزور أبو محمد كتير وكل مرة بيجيبله حاجة هدية.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-07'), 'نزار', 1, 'الموظف اللي في القسم اللي جنب مكتب أبو محمد وبيدخله كل يوم يوقّعله ورق', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-07'), 'قاسم', 2, 'حارس الأمن اللي بيفتح المصلحة كل صبح وعنده مفاتيح كل الأوض والمكاتب', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-07'), 'هاجر', 3, 'موظفة الأرشيف اللي بتروح مكتب أبو محمد كل يوم وبتجيبله ملفات وبتقعد فيه', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-07'), 'سعاد', 4, 'موظفة خدمة المواطنين اللي بتعرف كل الناس اللي بتيجي المصلحة وبتحب تتكلم كتير', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-07'), 'فراس', 5, 'راجل بيخلّص معاملة كبيرة في المصلحة وبيزور أبو محمد كل أسبوع وبيجيبله هدايا', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-08', 'ابتزاز', 'تسجيلات الاستوديو', 'في استوديو تسجيل صوتي في المهندسين، المطرب الشاب حازم لقى حد باعتله تسجيل خام ليه وهو بيغني أغنية لسه مطلعتش ومعاها رسالة: "ادفع ميت ألف ولا التسجيل ده هينزل على يوتيوب قبل ما الأغنية تطلع رسمي." حازم اتجنن عشان لو التسجيل نزل الأغنية هتبوظ وهيخسر كتير.', 3, 1, 'وسام', 'التسجيل الخام ده مكانش غير على كمبيوتر الاستوديو؛ الأغنية اتسجلت من أسبوع واللي سرقها كان عارف إنها مهمة جداً لحازم؛ محدش المفروض يقدر ياخد حاجة من الكمبيوتر غير صاحب الاستوديو واللي بيشتغلوا معاه.', 'وسام المهندس الصوتي كان آخر واحد سابها في الاستوديو يوم التسجيل؛ حد نقل الملف على هارد خارجي واتشال من سجلات النقل على الكمبيوتر؛ طارق كان عنده خناقة مع حازم على فلوس أغنية قديمة.', 'برنامج المراقبة على الكمبيوتر بيبين إن حد فتحه الساعة ٢ بالليل بعد ما الكل مشي؛ وسام هو الوحيد اللي عنده مفتاح الاستوديو غير صاحبه؛ الملف اتنقل على هارد وسام الشخصي؛ الرسالة اتبعتت من إيميل متعمل على جهاز كان متوصل بنت الاستوديو.', 'وسام هو اللي سرق التسجيل الخام عشان حازم مكانش بيقدّر شغله وبيدفعله أقل من حقه. وسام فتح الاستوديو بالليل ونقل الملف على الهارد بتاعه وبعتله رسالة التهديد عشان ياخد فلوس ويمشي يفتح استوديو لنفسه.', 'طارق صاحب الاستوديو كان بيبيع نسخ من تسجيلات تانية لناس من ورا حازم بس مش الأغنية دي؛ علاء كان بيستخدم كمبيوتر الاستوديو يشتغل على مشاريعه الخاصة بالليل من غير إذن.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-08'), 'وسام', 1, 'المهندس الصوتي اللي بيسجل كل أغاني حازم وعنده مفتاح الاستوديو وبيقعد فيه لوحده كتير', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-08'), 'طارق', 2, 'صاحب الاستوديو نفسه واللي بيأجره لحازم وعنده وصول لكل الأجهزة والملفات', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-08'), 'علاء', 3, 'عازف الموسيقى اللي بيشتغل مع حازم وبييجي الاستوديو كتير يتمرن', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-09', 'ابتزاز', 'فيديوهات المصنع', 'في مصنع أدوية في العاشر من رمضان، صاحب المصنع أبو خالد لقى رسالة فيها فيديوهات من كاميرات المصنع بتبيّن إنه بيستخدم مواد خام منتهية الصلاحية في التصنيع. اللي باعتها بيطلب نص مليون ولا الفيديوهات هتتبعت لوزارة الصحة. أبو خالد عارف إن الكاميرات دي محدش بيوصلها غير ناس معينة.', 5, 2, 'سارة، حسن', 'الفيديوهات من كاميرات المصنع الداخلية واللي محدش بيوصلها غير الإدارة والأمن؛ اللقطات مختارة بعناية وبتبين بالظبط اللي أبو خالد عايز يخبيه؛ الرسالة وصلت بعد ما أبو خالد رفض يزود مرتبات القسم كله؛ فيه حد عارف نظام الكاميرات كويس جداً.', 'سارة مهندسة الجودة اتخانقت مع أبو خالد قدام كل الناس الأسبوع اللي فات على موضوع المواد المنتهية؛ حسن مسؤول الأمن عنده صلاحيات الكاميرات كلها؛ حد نزّل الفيديوهات من السيرفر ومسح سجل التنزيل؛ أبو خالد كان بيهدد إنه يسرّح ناس من المصنع.', 'سجل الدخول على سيرفر الكاميرات بيبين إن حد دخل من كمبيوتر حسن؛ الفيديوهات اتعدلت بشكل احترافي وسارة عندها خبرة في المونتاج؛ سارة وحسن كانوا بيتقابلوا بره المصنع الفترة الأخيرة كتير؛ الرسالة اتبعتت من شريحة مدفوعة مسبقاً اتشريت من العاشر.', 'سارة هي اللي اختارت الفيديوهات وعملتلها مونتاج عشان تبين المخالفات بوضوح، وحسن هو اللي نزّلها من سيرفر الكاميرات عشان عنده الصلاحيات. الاتنين كانوا غضبانين من أبو خالد — سارة عشان هو بيغصبها تسكت على المخالفات وحسن عشان مبيزودش مرتبه من سنين.', 'محمد مدير الإنتاج كان عارف بموضوع المواد المنتهية وساكت عشان خايف على شغله؛ دينا المحاسبة كانت بتزوّر في فواتير الشراء عشان تغطي على المواد الرخيصة بأمر من أبو خالد؛ إسلام عامل الصيانة كان بياخد حاجات من المصنع لبيته.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-09'), 'محمد', 1, 'مدير الإنتاج اللي في المصنع من عشر سنين وعارف كل حاجة بتحصل جوه', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-09'), 'سارة', 2, 'مهندسة الجودة اللي دايماً بتتخانق مع أبو خالد على المعايير والمواد المستخدمة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-09'), 'حسن', 3, 'مسؤول الأمن والكاميرات واللي عنده صلاحيات على كل نظام المراقبة في المصنع', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-09'), 'دينا', 4, 'المحاسبة اللي بتتعامل مع كل فواتير الشراء وعارفة كام بيتصرف على إيه', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-09'), 'إسلام', 5, 'عامل الصيانة اللي بيلف المصنع كله وبيدخل كل مكان عشان يصلّح حاجات', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-10', 'ابتزاز', 'أسرار الشركة العقارية', 'في شركة عقارات كبيرة في مدينة نصر، المدير العام أبو ياسر بدأ يوصله رسايل فيها مستندات بتثبت إنه بيبيع شقق لناس وهي مش مسجلة أصلاً في الشهر العقاري. اللي بيبتزه عايز مليون جنيه ولا المستندات دي هتتبعت لجهاز حماية المستهلك والبرنامج التليفزيوني بتاع الشكاوي. أبو ياسر عارف إن الورق ده كان في الخزنة بتاعته بس.', 5, 2, 'مازن، شهد', 'المستندات دي مكانتش غير في خزنة أبو ياسر في مكتبه الخاص؛ اللي صورها كان عارف بالظبط أنهي ورق يصور من وسط ملفات كتير؛ الابتزاز بدأ بعد ما أبو ياسر قرر يصرف مكافآت لناس معينة ونسي ناس تانية؛ حد بيدخل المكتب بانتظام عنده فرصة يفتح الخزنة.', 'شهد المساعدة الشخصية بتاعت أبو ياسر كانت عارفة كود الخزنة عشان هو اداها إياه مرة يطلعله ورقة؛ مازن الشريك الخارجي كان بيدخل المكتب كل أسبوع وبيقعد لوحده فيه ساعات؛ فيه حد طبع المستندات في مكتبة في مدينة نصر ونسي يمسح سجل الطباعة؛ أبو ياسر كان ناوي ينهي الشراكة مع مازن.', 'سجل الطباعة في المكتبة بيبين إن حد طبع نفس المستندات من USB ييجي من أسبوعين؛ كود الخزنة اتغير مرة واحدة بس من سنة واللي يعرفه ناس محدودة؛ شهد ومازن كانوا بيتكلموا على الواتساب كتير رغم إنهم المفروض مش بينهم شغل مشترك؛ الرسايل بتيجي من إيميل كل مرة مختلف بس كلهم من نفس الجهاز.', 'مازن كان عارف إن أبو ياسر ناوي ينهي الشراكة وياخد كل المشاريع لوحده، فاتفق مع شهد إنها تفتح الخزنة وتصور المستندات وهو يبتزه بيها. شهد وافقت عشان أبو ياسر مكانش بيديها حقها ومازن وعدها بنسبة من الفلوس.', 'جلال مدير المبيعات كان عارف بموضوع الشقق المش مسجلة وساكت عشان بياخد عمولات؛ يارا المحاسبة كانت بتعمل كشوفات مالية مزدوجة بأمر من أبو ياسر ومش عايزة حد يعرف؛ باسل مسؤول البيانات كان بيسرّب أسعار الشقق لشركة منافسة.', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-10'), 'جلال', 1, 'مدير المبيعات اللي بيبيع الشقق وعارف كل تفاصيل المشاريع وبياخد عمولات كبيرة', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-10'), 'يارا', 2, 'المحاسبة اللي بتعمل كل الكشوفات المالية وعارفة فين كل قرش بيروح في الشركة', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-10'), 'شهد', 3, 'المساعدة الشخصية لأبو ياسر واللي عندها كود الخزنة وبتدخل مكتبه كل يوم', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-10'), 'مازن', 4, 'الشريك الخارجي اللي بيدخل المكتب كل أسبوع وأبو ياسر ناوي ينهي الشراكة معاه', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-10'), 'باسل', 5, 'مسؤول البيانات والسيستم في الشركة واللي عنده وصول لكل الملفات الرقمية', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-01', 'اختفاء دليل', 'ملف القضية اللي طار', 'في محكمة عابدين، كان فيه قضية رشوة كبيرة بتتنظر قدام القاضي. ملف القضية الأصلي اللي فيه كل الأدلة والورق اختفى من الأرشيف بالليل قبل الجلسة بيوم. من غير الملف ده القضية هتتحفظ والمتهم هيطلع براءة. خمس حد كان عندهم مفتاح الأرشيف أو دخلوه اليوم ده.', 5, 2, 'عم حسن، شريف', 'باب الأرشيف مكانش مكسور — يعني حد فتحه بمفتاح أو الباب كان مفتوح أصلاً; كاميرات المحكمة اتلاقت مطفية من الساعة ١٠ بالليل لحد الفجر; الفراش قال إنه سمع حد بيمشي في الدور التاني حوالي الساعة ١٢; فيه ورقة واحدة من الملف اتلاقت واقعة في السلم; المفتاح الاحتياطي بتاع الأرشيف مكانش في مكانه الصبح', 'كاميرا العمارة اللي قصاد المحكمة صورت عربية واقفة ورا المحكمة الساعة ١١ بالليل; العربية دي طلعت مسجلة باسم قريب المتهم في قضية الرشوة; واحد من الموظفين اتشاف وهو بيتكلم في تليفونه قدام المحكمة الساعة ١٠:٣٠ بالليل; اتلاقى كيس زبالة فيه ورق ممزق في صندوق الزبالة ورا المحكمة; بصمات على باب الأرشيف من جوه مش من بره', 'الورق الممزق اللي في الزبالة طلع فيه أجزاء من ملف القضية; تسجيلات موبايل واحد من المشتبه فيهم فيها مكالمة الساعة ٩ بالليل مع واحد مجهول بيقوله "الليلادي"; بصمات عم حسن اتلاقت على المفتاح الاحتياطي; شريف كان عنده نسخة من مفتاح الأرشيف عملها من شهرين وقال كانت "للطوارئ"; باقي الورق اتلاقى متحرق في جردل ورا المحكمة', 'عم حسن الفراش اتفق مع شريف الكاتب إنهم يسرقوا الملف مقابل ٥٠ ألف جنيه من قريب المتهم. عم حسن طفى الكاميرات وفتح الأرشيف بالمفتاح الاحتياطي، وشريف دخل وخد الملف ومزق نصه ورماه في الزبالة وحرق الباقي. كانوا فاكرين إن محدش هيلاحظ غير الصبح لما يكون الملف ضاع خلاص.', 'أحمد المحامي كان بيشتغل لحد بالليل وخرج الساعة ١١ — اتصور في كاميرات العمارة; منى الموظفة كانت بتدور على ملف تاني خالص في الأرشيف من يومين وعليها بصمات هناك; كريم الأمين كان مريض وجه ياخد أغراضه بالليل عشان مكانش جاي الصبح', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-01'), 'عم حسن', 1, 'الفراش بتاع المحكمة من ٣٠ سنة — بيعرف كل زاوية في المبنى ومعاه مفاتيح كل حاجة', true),
((SELECT id FROM cases WHERE case_code = 'E-01'), 'شريف', 2, 'كاتب التحقيقات في المحكمة — شغله إنه ينقل الملفات وينظمها ويعرف أماكنها كلها', true),
((SELECT id FROM cases WHERE case_code = 'E-01'), 'أحمد', 3, 'محامي شاب من مكتب في وسط البلد — كان بيشتغل على قضية تانية في نفس المحكمة', false),
((SELECT id FROM cases WHERE case_code = 'E-01'), 'منى', 4, 'موظفة الأرشيف اللي بتنظم الملفات — أول واحدة اكتشفت إن الملف مش موجود الصبح', false),
((SELECT id FROM cases WHERE case_code = 'E-01'), 'كريم', 5, 'أمين المحكمة المسؤول عن الأمن — كان في إجازة مرضية اليوم اللي الملف اختفى فيه', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-02', 'اختفاء دليل', 'الفلاشة اللي ضاعت', 'في شركة محاسبة في مدينة نصر، كان المدير المالي عنده فلاشة عليها كل بيانات التلاعب في الحسابات اللي كان هيقدمها للنيابة الصبح. حط الفلاشة في الخزنة بتاعته وراح البيت. لما رجع الصبح لقى الخزنة مفتوحة والفلاشة مش موجودة. تلات حد بس كانوا في الشركة بالليل.', 3, 1, 'دينا', 'الخزنة اتفتحت بالكود مش بالكسر — يعني حد عارف الرقم; كاميرا الشركة بتوري إن التلات موظفين كانوا موجودين لحد الساعة ١١ بالليل; مكانش فيه أي أثر لحد غريب دخل المكان', 'دينا سألت المدير المالي عن الخزنة قبلها بيومين وقالت "عايزة أحط ورق مهم"; اتلاقت بصمات على الخزنة بتاعت التلات موظفين; مسجل الدخول والخروج بيقول إن واحد رجع الشركة الساعة ٢ الصبح', 'كاميرا المبنى من بره صورت دينا وهي راجعة الساعة ٢ الصبح لوحدها; اتلاقت فلاشة فاضية في درج مكتب دينا — نفس الماركة والشكل; سجل الكمبيوتر بتاع دينا فيه إنها فتحت ملفات من فلاشة USB الساعة ٢:٣٠ الفجر وعملت format', 'دينا كانت عارفة إن البيانات اللي على الفلاشة فيها اسمها هي كمان عشان كانت شريكة في التلاعب. رجعت الشركة بالليل وفتحت الخزنة بالكود اللي كانت شافت المدير بيدخله. نسخت الفلاشة على جهازها وبعدين عملتلها format ورجعتها مكانها — بس اتلخبطت ورجعتها في درجها بدل الخزنة.', 'رامي المحاسب كان بيشتغل أوفر تايم عشان عنده ديدلاين كبير وعليه ضغط — وكان عنده مفتاح المكتب; مصطفى مسؤول الـ IT كان بيعمل صيانة للسيرفر بالليل وعنده صلاحية دخول كل المكاتب', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-02'), 'دينا', 1, 'محاسبة في الشركة من ٥ سنين — بتعرف كل حاجة عن الحسابات والأرقام', true),
((SELECT id FROM cases WHERE case_code = 'E-02'), 'رامي', 2, 'محاسب جديد في الشركة — بيشتغل أوفر تايم كتير عشان يثبت نفسه', false),
((SELECT id FROM cases WHERE case_code = 'E-02'), 'مصطفى', 3, 'مسؤول الـ IT بتاع الشركة — بيعمل صيانة ليلية للسيرفرات كل أسبوع', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-03', 'اختفاء دليل', 'تسجيل الكاميرا اللي اتمسح', 'في مستشفى جامعي في القصر العيني، مريض مات في ظروف غريبة بالليل. الكاميرا اللي قدام أوضته كانت مسجلة كل حاجة، بس لما راحوا يشوفوا التسجيل لقوه اتمسح من الساعة ١٢ لحد ٤ الفجر. خمس حد كانوا موجودين في الدور ده بالليل وعندهم صلاحية يدخلوا أوضة السيرفر.', 5, 2, 'هاجر، طارق', 'تسجيلات باقي الكاميرات في الأدوار التانية شغالة عادي — الدور ده بس اللي اتمسح; أوضة السيرفر مفيهاش كاميرا لوحدها; حد كتب الباسوورد بتاع السيستم على ورقة ولزقها جوه درج في أوضة السيرفر; الممرضة بتاعت الليل قالت إنها شافت حد بيدخل أوضة السيرفر حوالي الساعة ١ بس مشافتش وشه; المريض اللي مات كان حالته بتتحسن قبلها بيوم', 'سجل الدخول لأوضة السيرفر بيقول إن الكارت بتاع هاجر اتستخدم الساعة ١٢:٤٥; طارق كان المسؤول عن المريض بالليل وكان آخر واحد دخل الأوضة قبل ما يموت; تقرير الصيدلية بيقول إن جرعة مسكنات زيادة اتصرفت بالليل; المريض كان بيهدد إنه يرفع قضية على المستشفى', 'لوج السيرفر فيه إن الملفات اتمسحت من جهاز هاجر بالتحديد; طارق كان بيتكلم مع هاجر في واتساب الساعة ١٢ وباعتلها "جاهزة؟"; كاميرا الدور اللي تحت صورت طارق وهو طالع السلم الساعة ١٢:٣٠ مع إنه قال كان في محطة التمريض; تقرير الطب الشرعي الأولي بيقول إن المريض أخد جرعة مسكنات أكتر من اللازم; هاجر طلبت نقل فجأة من القسم تاني يوم', 'هاجر وطارق كانوا الاتنين متورطين في إهمال طبي مع المريض ده قبل كده. لما المريض هددهم إنه هيرفع قضية، طارق زود جرعة المسكنات بالليل، وهاجر راحت أوضة السيرفر ومسحت تسجيل الكاميرا عشان محدش يشوف طارق وهو داخل الأوضة. الاتنين فاكرين إن من غير الفيديو محدش يقدر يثبت حاجة.', 'نور الممرضة كانت نايمة في محطة التمريض ومحرجة إنها تقول عشان ده غلط; أحمد الدكتور المقيم كان بيراجع ملفات مرضى تانيين وبصماته على سيرفر الملفات الطبية; إسلام فني الصيانة كان بيصلح التكييف في نفس الدور ودخل أوضة السيرفر ياخد عدة', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-03'), 'هاجر', 1, 'مسؤولة نظم المعلومات في المستشفى — بتتحكم في كل الكاميرات والسيرفرات', true),
((SELECT id FROM cases WHERE case_code = 'E-03'), 'طارق', 2, 'دكتور متخصص في العناية المركزة — كان المسؤول عن المريض في الشيفت الليلي', true),
((SELECT id FROM cases WHERE case_code = 'E-03'), 'نور', 3, 'ممرضة الشيفت الليلي — بتقعد في محطة التمريض وبتراقب المرضى', false),
((SELECT id FROM cases WHERE case_code = 'E-03'), 'أحمد', 4, 'دكتور مقيم في أول سنة — بيتعلم وبيساعد في الحالات بالليل', false),
((SELECT id FROM cases WHERE case_code = 'E-03'), 'إسلام', 5, 'فني صيانة بيشتغل شيفت ليلي — بيلف على كل الأدوار يصلح أي عطل', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-04', 'اختفاء دليل', 'العقد اللي ضاعت صفحته', 'في مكتب محاماة في وسط البلد، كان فيه عقد شراكة بين شركتين كبار. الصفحة اللي فيها بند تقسيم الأرباح اختفت من العقد الأصلي اللي محطوط في خزنة المكتب. من غير الصفحة دي، الشريك الصغير هيخسر حقه في ٤٠٪ من الأرباح. تلات حد بس كان عندهم وصول للخزنة.', 3, 1, 'حسام', 'الخزنة مفيهاش أي أثر كسر — اتفتحت بالكود العادي; العقد كان ٢٠ صفحة ودلوقتي ١٩ — الصفحة رقم ١٤ هي اللي ناقصة; آخر مرة العقد اتراجع كان من أسبوع وكان كامل', 'حسام طلب من السكرتيرة تصور العقد قبلها بيومين بس مرجعش الأصل على طول; لوج الخزنة بيقول إنها اتفتحت ٣ مرات الأسبوع ده; واحد من التلاتة اتصل بالشريك الكبير يوم ما الصفحة اختفت', 'المكالمة اللي اتعملت للشريك الكبير طلعت من موبايل حسام; الطابعة بتاعت المكتب سجلت إن حد طبع صورة من صفحة ١٤ قبل ما تختفي بيوم — من جهاز حسام; شهادة الحارس بتقول إن حسام كان آخر واحد ساب المكتب يوم الاختفاء وقعد لحد ١٠ بالليل', 'حسام كان بيمثل الشريك الكبير في السر. الشريك الكبير وعده بعمولة ضخمة لو الصفحة دي اختفت. حسام صور الصفحة لنفسه كضمان، وبعدين فتح الخزنة وشال الصفحة الأصلية ومزقها في التواليت. كان فاكر إن محدش هيلاحظ غير لما يكون فات الأوان.', 'فاطمة المحامية الشريكة كانت بتراجع العقد قبلها بأسبوع عشان عندها قضية شبهه وعليها بصمات على الخزنة; ياسمين السكرتيرة كانت بتصور أوراق كتير في نفس الفترة وعندها وصول للخزنة عشان شغلها', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-04'), 'حسام', 1, 'محامي كبير في المكتب من ١٥ سنة — بيمسك أكبر القضايا التجارية', true),
((SELECT id FROM cases WHERE case_code = 'E-04'), 'فاطمة', 2, 'محامية شريكة في المكتب — بتشتغل على قضايا العقود والشراكات', false),
((SELECT id FROM cases WHERE case_code = 'E-04'), 'ياسمين', 3, 'سكرتيرة المكتب — بتنظم كل الملفات والمواعيد وعندها مفاتيح كل حاجة', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-05', 'اختفاء دليل', 'السلاح اللي اتمسح', 'في قسم شرطة بولاق، كان فيه سلاح مضبوط في قضية قتل كبيرة — مسدس عليه بصمات المتهم الرئيسي. السلاح كان في عهدة المخزن. لما جه ميعاد تسليمه للنيابة، لقوا إن البصمات اتمسحت بالكامل والسلاح اتنضف. من غير البصمات دي القضية هتقع. خمس حد كان عندهم وصول للمخزن.', 5, 2, 'أبو سمير، مي', 'السلاح لسه موجود في المخزن بس اتنضف بمادة كيماوية شالت كل البصمات; دفتر المخزن فيه ٥ أسامي دخلوا في آخر ٣ أيام; المخزن مفيهوش كاميرا — بس فيه دفتر تسجيل يدوي', 'واحد من الأسامي في الدفتر كتب وقت دخول غلط — مش مطابق لكاميرا المدخل الرئيسي; أبو سمير أمين المخزن دخل المخزن ٣ مرات في يوم واحد مع إن العادي مرة واحدة; اتلاقت قفازات بلاستيك في زبالة المخزن مع إن محدش بيلبس قفازات هناك', 'القفازات اللي اتلاقت عليها أثر نفس المادة الكيماوية اللي اتمسح بيها السلاح; مي بنت المتهم الرئيسي في القضية — الموضوع ده مكانش معروف عشان اسم أبوها التاني; مكالمات أبو سمير فيها ٧ مكالمات مع نمرة مي في آخر أسبوع; مي دخلت المخزن يوم ما البصمات اتمسحت وقالت "جاية أسلم أوراق"', 'أبو سمير كان بياخد رشوة من عيلة المتهم عن طريق مي بنت المتهم. مي راحتله في المخزن وسلمته فلوس، وهو لبس قفازات ومسح البصمات بمادة كيماوية جابتهاله مي. كتب في الدفتر إن مي جت تسلم "أوراق" وخلاص. كانوا فاكرين إن محدش هيربط بينها وبين المتهم.', 'عمرو الضابط كان بيحقق في القضية وداخل المخزن يراجع الأدلة بشكل طبيعي; سارة المحققة كانت بتكتب تقرير ودخلت تاخد صور للسلاح قبلها بيومين; محمد الأمين المساعد كان بينضف المخزن ولمس حاجات كتير بس مش السلاح', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-05'), 'أبو سمير', 1, 'أمين مخزن الأدلة في القسم من ٢٠ سنة — مفيش حاجة تدخل أو تطلع من غير ما يعرف', true),
((SELECT id FROM cases WHERE case_code = 'E-05'), 'مي', 2, 'بنت بتيجي القسم كتير "تسلم أوراق" — محدش يعرف عنها حاجة كتير', true),
((SELECT id FROM cases WHERE case_code = 'E-05'), 'عمرو', 3, 'ضابط مباحث شغال على قضية القتل — أكتر واحد محتاج الدليل ده يفضل سليم', false),
((SELECT id FROM cases WHERE case_code = 'E-05'), 'سارة', 4, 'محققة جنائية بتاخد صور وتوثق الأدلة — دخلت المخزن أكتر من مرة الأسبوع ده', false),
((SELECT id FROM cases WHERE case_code = 'E-05'), 'محمد', 5, 'أمين مساعد بيساعد في ترتيب المخزن — لسه جديد في الشغل ومش فاهم كل النظام', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-06', 'اختفاء دليل', 'كشف الحضور اللي اختفى', 'في مصلحة حكومية في العتبة، كان فيه تحقيق في اختلاس فلوس كتير. كشف الحضور اللي بيثبت إن الموظف المتهم كان موجود أيام ما الفلوس اتسرقت اختفى من الأرشيف. من غير كشف الحضور ده، المتهم يقدر يقول إنه كان في إجازة والقضية تقع. خمس حد كان عندهم سبب يدخلوا الأرشيف.', 5, 2, 'هدى، إسلام', 'الأرشيف بتاع المصلحة فيه آلاف الملفات ومحدش بيلاحظ لو ملف ضاع بسرعة; باب الأرشيف بيتقفل بمفتاح عادي ومعظم الموظفين القدام عندهم نسخة; كشف الحضور اللي اختفى كان بتاع شهر مارس بس — باقي الشهور موجودة', 'هدى كانت بتشتغل في ترتيب الأرشيف الأسبوع اللي فات وقعدت لوحدها ساعتين; إسلام اتشاف وهو شايل ملفات من الأرشيف وقال "دي ملفات شغلي"; الموظف المتهم بالاختلاس طلع قريب هدى — خالها بالظبط; ملفات شهر فبراير ومارس كانت جنب بعض وملف فبراير مكانه اتغير', 'كاميرا المدخل صورت هدى وهي خارجة بشنطة أكبر من العادي يوم ما الكشف اختفى; إسلام طلع بيشتغل في مكتب محاماة بتاع خال هدى — المتهم بالاختلاس — بالليل كشغل إضافي; رسايل واتساب بين هدى وإسلام فيها "الملف اللي قلتلك عليه — لازم يختفي قبل آخر الأسبوع"; اتلاقى كشف حضور ممزق في كيس زبالة في الشارع ورا المصلحة', 'هدى كانت عايزة تنقذ خالها من قضية الاختلاس فاتفقت مع إسلام اللي كان بيشتغل مع خالها. هدى قعدت في الأرشيف لوحدها وطلعت كشف الحضور في شنطتها، وإسلام استلمه منها بره ومزقه ورماه في الزبالة. كانوا فاكرين إن ورقة حضور قديمة محدش هيدور عليها.', 'مصطفى رئيس القسم كان بيدور على ملفات تانية في الأرشيف وبصماته في كل حتة; فاطمة الموظفة كانت بتصور ملفات لنفسها عشان بتجهز لنقل من المصلحة وخايفة حد يعرف; عمرو المراجع الداخلي هو اللي اكتشف إن الكشف ناقص وده خلاه يبان مريب', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-06'), 'هدى', 1, 'موظفة قديمة في المصلحة — مسؤولة عن ترتيب الأرشيف وبتعرف مكان كل ورقة', true),
((SELECT id FROM cases WHERE case_code = 'E-06'), 'إسلام', 2, 'موظف في قسم الحسابات — هادي ومحدش بياخد باله منه', true),
((SELECT id FROM cases WHERE case_code = 'E-06'), 'مصطفى', 3, 'رئيس القسم — بيحب يراجع كل حاجة بنفسه وبينزل الأرشيف كتير', false),
((SELECT id FROM cases WHERE case_code = 'E-06'), 'فاطمة', 4, 'موظفة بتجهز للنقل — بتصور ملفات كتير وبتقعد في الأرشيف', false),
((SELECT id FROM cases WHERE case_code = 'E-06'), 'عمرو', 5, 'المراجع الداخلي — هو اللي اكتشف إن كشف الحضور ناقص وبلّغ', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-07', 'اختفاء دليل', 'صورة الموبايل اللي اتمسحت', 'في بيت في الهرم، واحدة صورت جارها وهو بيرمي كيس فيه حاجات مسروقة في الترعة. الصورة كانت الدليل الوحيد في البلاغ. تاني يوم الصورة اتمسحت من موبايلها وهي نايمة ومحدش كان في البيت غير تلات حد. الموبايل مكانش عليه باسوورد.', 3, 1, 'كريم', 'الموبايل كان على الكومودينو في أوضة النوم والبيت كان مفتوح; الصورة اتمسحت الساعة ٣ الفجر حسب سجل الموبايل; التلات حد اللي في البيت كلهم كانوا عارفين إن الصورة موجودة عشان صاحبة الموبايل قالتلهم', 'كريم ابن الجارة — أمه بتقعد كتير مع الجار اللي في الصورة وبينهم صداقة قوية; الموبايل كان فيه إن حد فتحه الساعة ٢:٥٠ الفجر وقعد ١٠ دقايق; كريم أوضته أقرب أوضة لأوضة صاحبة الموبايل', 'كريم باعت لأمه رسالة الساعة ٢ الفجر قالها "متقلقيش هتعرف خبر حلو الصبح"; بصمة كريم اتلاقت على الموبايل مع إنه قال "معمري مسكته"; سجل الموبايل بيقول إن الصورة اتمسحت وبعدها اتمسحت من المحذوفات كمان — يعني اللي عمل كده كان فاهم', 'كريم عرف من أمه إن الصورة هتورط الجار اللي أمه بتحبه. راح بالليل وهو عارف إن الموبايل مفيهوش باسوورد، فتحه ومسح الصورة ومسحها من سلة المحذوفات كمان عشان يضمن إنها ضاعت خالص. حصل كل ده وصاحبة الموبايل نايمة.', 'فاطمة أخت صاحبة الموبايل كانت صاحية بالليل بتتفرج على مسلسل وقالت مسمعتش حاجة — بس هي اللي قالت للجيران كلهم عن الصورة; أحمد جوز صاحبة الموبايل كان نايم من ١٠ بالليل وبيشخر — بس هو كان زعلان إن مراته بلّغت', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-07'), 'كريم', 1, 'ابن الجارة — شاب في الجامعة بيفهم في التكنولوجيا وبيقعد عندهم كتير', true),
((SELECT id FROM cases WHERE case_code = 'E-07'), 'فاطمة', 2, 'أخت صاحبة الموبايل — بتسهر كتير وبتعرف أخبار كل الجيران', false),
((SELECT id FROM cases WHERE case_code = 'E-07'), 'أحمد', 3, 'جوز صاحبة الموبايل — راجل هادي مش بيحب المشاكل مع الجيران', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-08', 'اختفاء دليل', 'الظرف المختوم اللي اتفتح', 'في شركة مقاولات في مدينة نصر، المدير القديم قبل ما يتوفى ساب ظرف مختوم فيه أسامي الناس اللي بتاخد رشاوي في الشركة. الظرف كان في خزنة المكتب. لما المحامي جه يفتحه رسمي، لقى الظرف مفتوح وفاضي. الورقة اللي جواه اختفت. خمس حد كانوا عارفين بالظرف وعندهم وصول للخزنة.', 5, 2, 'منى، رامي', 'الظرف لسه موجود في الخزنة بس مفتوح ومفيهوش حاجة; الخزنة اتفتحت بالكود — مفيش أثر كسر; المدير القديم مات من أسبوعين والظرف كان المفروض يتفتح بعد الوفاة', 'كود الخزنة كان يعرفه ٤ حد بس — المدير اللي مات والتلاتة اللي معاهم; منى سكرتيرة المدير القديم كانت أقرب واحدة ليه وكانت عارفة الكود; لوج الكارت بيقول إن حد دخل المكتب يوم الجمعة — يوم إجازة; اتلاقى رماد ورقة متحرقة في طفاية السجاير على البلكونة', 'رماد الورقة فيه حبر أزرق — نفس نوع الحبر اللي المدير كان بيستخدمه; كاميرا المبنى صورت منى ورامي داخلين مع بعض يوم الجمعة الساعة ٢ الضهر; منى اسمها كان في قايمة الرشاوي — المدير قالها كده قبل ما يموت عشان "يحذرها"; رامي مدير الحسابات — هو كمان كان اسمه في القايمة حسب ما المدير القديم لمّح لحد', 'منى عرفت من المدير القديم قبل ما يموت إن اسمها في الورقة. كلمت رامي اللي كان خايف هو كمان. راحوا يوم الجمعة مع بعض، منى فتحت الخزنة بالكود اللي عارفاه، ورامي طلع الورقة وحرقها في البلكونة. فاكرين إن محدش هيعرف كان مكتوب فيها إيه.', 'حسام المدير الجديد كان بيدور في مكتب المدير القديم على ملفات شغل وبصماته في كل حتة; هاجر المحاسبة كانت خايفة إن اسمها في الورقة مع إنها معملتش حاجة وده خلاها تتصرف بتوتر; طارق مساعد المدير القديم كان عنده نسخة من الكود بس مسافر من أسبوع', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-08'), 'منى', 1, 'سكرتيرة المدير القديم الله يرحمه — كانت إيده اليمين وعارفة كل أسراره', true),
((SELECT id FROM cases WHERE case_code = 'E-08'), 'رامي', 2, 'مدير الحسابات في الشركة — بيمسك كل الفلوس اللي داخلة وخارجة', true),
((SELECT id FROM cases WHERE case_code = 'E-08'), 'حسام', 3, 'المدير الجديد اللي مسك بعد الوفاة — لسه بيفهم إيه اللي بيحصل', false),
((SELECT id FROM cases WHERE case_code = 'E-08'), 'هاجر', 4, 'محاسبة في الشركة — شغالة من ٨ سنين وقلقانة على مستقبلها', false),
((SELECT id FROM cases WHERE case_code = 'E-08'), 'طارق', 5, 'مساعد المدير القديم — كان مسافر وقت ما الظرف اتفتح بس عنده الكود', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-09', 'اختفاء دليل', 'تقرير المعمل اللي طار', 'في مستشفى خاص في المعادي، مريض اتسمم وتقرير المعمل اللي بيبين نوع السم اختفى من الملف الطبي قبل ما يوصل للنيابة. التقرير كان مطبوع ومحطوط في ملف المريض في محطة التمريض. تلات حد بس كانوا في الدور ده وقت ما التقرير اختفى.', 3, 1, 'هدى', 'ملف المريض لسه موجود بس التقرير اللي كان فيه مش موجود; محطة التمريض مفيهاش كاميرا — بس الدور فيه كاميرا في الممر; التقرير اتطلب الساعة ١٠ الصبح واختفى قبل الساعة ٢ الضهر', 'هدى الممرضة كانت بتأكل لوحدها في محطة التمريض وقت الغدا — كان فيها لوحدها نص ساعة; المريض اللي اتسمم كان خاطب بنت أخت هدى وهدى مكانتش موافقة; فيه حد اشترى ماكينة تمزيق ورق جديدة للدور من أسبوع', 'ماكينة تمزيق الورق فيها بقايا ورقة فيها كلمة "نتائج" و"عينة" — نفس شكل ورق المعمل; هدى هي اللي طلبت شراء ماكينة التمزيق الجديدة; كاميرا الممر مفيهاش أي حد غريب دخل محطة التمريض — يعني حد من التلاتة اللي موجودين في الدور', 'هدى كانت عارفة إن تقرير المعمل هيوري إن السم اللي المريض أخده نوع معين بيستخدم في المستشفيات. هي مكانتش بتحب المريض ده وكانت عايزة القضية تتحفظ. وقت ما كانت لوحدها في محطة التمريض، طلعت التقرير من الملف وحطته في ماكينة التمزيق اللي هي أصلاً جابتها عشان اللحظة دي.', 'مصطفى الدكتور المعالج كان بيراجع ملفات كتير في نفس الوقت وبيمسك الملفات كلها — بصماته على كل حاجة; سارة الممرضة التانية كانت في إجازة نص يوم ورجعت الساعة ١ — يعني كانت موجودة وقت ما التقرير اختفى', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
((SELECT id FROM cases WHERE case_code = 'E-09'), 'هدى', 1, 'ممرضة قديمة في المستشفى من ١٢ سنة — كل الدكاترة بيثقوا فيها', true),
((SELECT id FROM cases WHERE case_code = 'E-09'), 'مصطفى', 2, 'الدكتور المعالج بتاع المريض — مسؤول عن كل الملفات الطبية', false),
((SELECT id FROM cases WHERE case_code = 'E-09'), 'سارة', 3, 'ممرضة شابة في نفس الدور — رجعت من إجازة نص يوم وقت الحادثة', false);
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-10', 'اختفاء دليل', 'الهارد اللي اتفرمت', 'في ورشة كمبيوتر في بولاق أبو العلا، واحد ساب اللاب توب بتاعه يتصلح وعليه فيديوهات بتثبت إن شريكه في المحل بيسرق منه. لما رجع ياخد اللاب توب، لقى الهارد اتفرمت بالكامل والفيديوهات ضاعت. خمس حد كانوا في الورشة وعندهم وصول للاب توب.', 5, 2, 'عم حسن، نور', 'الهارد اتفرمت فورمات كامل مش بس الفيديوهات — اللاب توب رجع زي الجديد; سجل الورشة بيقول إن اللاب توب دخل يوم الأحد والزبون كان جاي ياخده يوم التلات; الفورمات اتعمل يوم الاتنين بالليل حسب تاريخ السيستم', 'عم حسن صاحب الورشة اتصل بيه حد مجهول يوم الأحد بالليل واتكلموا ١٥ دقيقة; نور الفنية اللي بتصلح الأجهزة هي اللي كانت ماسكة اللاب توب وعندها الباسوورد; الشريك اللي في الفيديوهات طلع صاحب عم حسن من زمان; فيه فلوس زيادة ٥ آلاف جنيه ظهرت في حساب الورشة يوم الاتنين', 'المكالمة المجهولة اللي جت لعم حسن طلعت من موبايل الشريك اللي في الفيديوهات; عم حسن طلب من نور تعمل "صيانة شاملة" للاب توب يوم الاتنين مع إن الزبون طالب تصليح الشاشة بس; نور اعترفت إن عم حسن قالها "فرمت الجهاز ده وأنا هحاسبك زيادة"; الـ ٥ آلاف جنيه اتحولوا من حساب الشريك اللي في الفيديوهات', 'عم حسن صاحبه القديم — الشريك اللي في الفيديوهات — اتصل بيه وقاله إن فيه لاب توب في ورشته عليه فيديوهات هتخرب بيته. عم حسن وافق يساعده مقابل ٥ آلاف جنيه، وطلب من نور تفرمت الجهاز كله. نور عملت اللي عم حسن قالها عليه عشان هو المعلم بتاعها واداها جزء من الفلوس.', 'رامي متدرب في الورشة كان بيلعب على كمبيوتر تاني وبصماته على أجهزة كتير في الورشة; دينا بتاعت الحسابات لقت الـ ٥ آلاف وسجلتها ومش عارفة مصدرها — بس ده خلاها تبان مريبة; طارق زبون كان بيستلم جهازه ودخل الورشة يوم الاتنين — يعني كان موجود وقت الفورمات', 'production_ready', 'ar-EG');
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES
