((SELECT id FROM cases WHERE case_code = 'E-10'), 'نور', 2, 'فنية كمبيوتر شاطرة — بتصلح أي جهاز وبتسمع كلام عم حسن في كل حاجة', true),
((SELECT id FROM cases WHERE case_code = 'E-10'), 'رامي', 3, 'متدرب في الورشة — لسه بيتعلم وبيلمس كل الأجهزة', false),
((SELECT id FROM cases WHERE case_code = 'E-10'), 'دينا', 4, 'بتاعت الحسابات في الورشة — بتسجل كل جنيه داخل وخارج', false),
((SELECT id FROM cases WHERE case_code = 'E-10'), 'طارق', 5, 'زبون كان جاي يستلم جهازه — قعد في الورشة شوية وشاف اللي بيحصل', false);
